import type { Drill } from "./types";

// Engineer / senior drills, keyed by module slug — 25 per module.
// Senior engineering executive (director/VP/CTO-adjacent) who reports to or sits
// with the C-suite: board narratives, platform strategy, incident comms,
// investment cases, org design, QBRs, vendor negotiations. Merged into course.ts.
export const ENGINEER_SENIOR_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-eng-senior-01","level":"senior","profession":"engineer","title":"The board update that buries the win","scenario":"Your platform migration finished two weeks early and $400K under budget. Your draft board update opens with three paragraphs on the migration's history and methodology before the outcome appears.","task":"Write the first two sentences of the board update, leading with the result.","tips":["Sentence one carries the headline: done early, under budget.","Boards read the first line and skim the rest — earn the skim.","History and methodology are appendix material."],"focus":["structure","impact"],"placeholder":"The platform migration is complete — two weeks early and $400K under budget."},
    {"id":"lead-eng-senior-02","level":"senior","profession":"engineer","title":"The headcount ask hidden in context","scenario":"You need the CEO to approve 12 additional engineers for the payments team before the quarter closes, or the compliance deadline slips. Your draft email spends four paragraphs on market context before the ask surfaces.","task":"Write a 2-3 sentence email opening that puts the ask and the deadline first.","tips":["Lead with what you need, from whom, by when.","One sentence of consequence is stronger than four of background.","A CEO should know the decision required before the second sentence."],"focus":["clarity","impact"],"placeholder":"I need approval for 12 payments engineers by Friday —"},
    {"id":"lead-eng-senior-03","level":"senior","profession":"engineer","title":"The incident brief that starts with the timeline","scenario":"Checkout was degraded for 47 minutes this morning; roughly 3% of transactions failed and the issue is resolved. Your draft to the exec team opens with a minute-by-minute timeline before stating customer impact or current status.","task":"Write a 2-3 sentence incident summary that leads with impact and status.","tips":["Executives need three things first: what broke, who it hurt, is it over.","The timeline is evidence — attach it below the headline.","State resolution status in sentence one, not paragraph three."],"focus":["structure","clarity"],"placeholder":"Checkout was degraded for 47 minutes this morning; ~3% of transactions failed. It is fully resolved."},
    {"id":"lead-eng-senior-04","level":"senior","profession":"engineer","title":"The build-vs-buy verdict on page six","scenario":"After an eight-week evaluation, your recommendation is clear: buy the vendor billing platform rather than build. Your memo to the CFO walks through the full evaluation before the recommendation appears on page six.","task":"Write an opening sentence for the memo that states the recommendation and the core reason.","tips":["Verdict first: buy, and the one number that justifies it.","The eight weeks of analysis earn credibility as support, not as the opening.","If the CFO reads one sentence, it should contain the decision."],"focus":["structure","clarity"],"placeholder":"Recommendation: buy. Building would cost 3x more over five years —"},
    {"id":"lead-eng-senior-05","level":"senior","profession":"engineer","title":"The cloud-spend answer the CFO wants","scenario":"The CFO emailed one question: why did cloud spend jump 18% last month? You know the answer — a planned data-migration workload that ends this week — but your draft opens with a tour of your cost-monitoring practices.","task":"Write a 2-sentence reply that answers the question in the first sentence.","tips":["Answer the question asked, in sentence one.","Reassurance about your practices comes after the answer, if at all.","Include the end date — that is the part that lowers the temperature."],"focus":["clarity","concision"],"placeholder":"The 18% jump is the planned data migration, which finishes this week —"},
    {"id":"lead-eng-senior-06","level":"senior","profession":"engineer","title":"The reorg announcement that eases in","scenario":"You are announcing at all-hands that the platform and infrastructure teams are merging under one VP. Your draft opens with five minutes of company-strategy preamble before anyone learns what is actually changing.","task":"Write the first two sentences of the announcement, leading with the change itself.","tips":["People cannot hear strategy while waiting to learn their fate — state the change first.","Name what changes, for whom, and when in the opening.","The why matters and comes immediately second."],"focus":["clarity","structure"]},
    {"id":"lead-eng-senior-07","level":"senior","profession":"engineer","title":"The vulnerability disclosure to the CEO","scenario":"Your security team found a critical vulnerability in the customer API. No evidence of exploitation, patch ships in six hours. You are messaging the CEO directly and your instinct is to open with how the scan process caught it.","task":"Write a 2-3 sentence Slack message that leads with severity, exposure, and the fix timeline.","tips":["Lead with the classification and whether customers are affected.","'No evidence of exploitation' belongs in the first two sentences.","Process credit can wait for the retro."],"focus":["clarity","impact"],"placeholder":"We found a critical vulnerability in the customer API — no evidence of exploitation, patch live in six hours."},
    {"id":"lead-eng-senior-08","level":"senior","profession":"engineer","title":"The QBR that opens with housekeeping","scenario":"Your engineering QBR slot is 20 minutes with the CEO and CFO. The quarter's verdict: shipped the two committed launches, reliability improved, hiring missed by four. Your current opening slide is a team org chart and an agenda.","task":"Write the 1-2 sentence spoken opening that gives the quarter's verdict up front.","tips":["Open with the scoreboard: what you committed, what landed, what missed.","Agendas and org charts are warm-up — executives want the verdict.","Naming the miss up front buys credibility for everything after."],"focus":["structure","impact"],"placeholder":"We delivered both committed launches and improved uptime to 99.95% — and missed hiring by four."},
    {"id":"lead-eng-senior-09","level":"senior","profession":"engineer","title":"The renewal recommendation in the last line","scenario":"The observability vendor contract renews in 30 days at $900K. You have negotiated them down to $720K and recommend renewing. Your note to the CFO recounts the negotiation history before the recommendation appears in the final line.","task":"Rewrite the opening so the recommendation and the number lead.","tips":["Recommendation and price in sentence one.","The negotiation story supports the number — it is not the news.","End the opening with what you need: sign-off by a date."],"focus":["clarity","structure"],"placeholder":"Recommend renewing the observability contract at $720K — down from $900K."},
    {"id":"lead-eng-senior-10","level":"senior","profession":"engineer","title":"The launch slip you have to own","scenario":"The flagship product launch the CEO announced to the board will slip six weeks. You are drafting the message to the executive team, and your current version explains three vendor delays before the new date appears.","task":"Write a 2-3 sentence message that states the new date in the first sentence.","tips":["The new date is the message — lead with it.","Causes get one sentence, not three paragraphs.","Close with what you are doing to protect the new date."],"focus":["clarity","impact"],"placeholder":"The launch moves from March 4 to April 15."},
    {"id":"lead-eng-senior-11","level":"senior","profession":"engineer","title":"The board member's email","scenario":"A board member emailed you directly: \"Are we exposed to the vulnerability in the news this week?\" You have checked — you are not exposed — but your draft opens with an explanation of your patching cadence.","task":"Write a 2-sentence reply that answers the question first.","tips":["First word should carry the answer: no.","Then one sentence of evidence so the 'no' is credible.","Board members forward these emails — write the version that forwards well."],"focus":["clarity","concision"],"placeholder":"No — we are not exposed."},
    {"id":"lead-eng-senior-12","level":"senior","profession":"engineer","title":"The tech-debt pre-read","scenario":"You are sending the executive committee a pre-read requesting $3M over two quarters to retire the legacy order system, which caused 60% of last year's incidents. Your draft opens with the system's twelve-year history.","task":"Write the pre-read's first two sentences, leading with the ask and the payoff.","tips":["Dollar amount, duration, and outcome in sentence one.","The 60%-of-incidents figure is your strongest line — put it early.","History explains how you got here; it does not open the case."],"focus":["structure","impact"],"placeholder":"I'm asking for $3M over two quarters to retire the legacy order system — the source of 60% of last year's incidents."},
    {"id":"lead-eng-senior-13","level":"senior","profession":"engineer","title":"The escalation reply to a customer CTO","scenario":"The CTO of your largest customer escalated a data-sync failure directly to you overnight. The issue was fixed at 6 a.m. and their data is intact. Your draft reply opens with an apology paragraph before mentioning the fix.","task":"Write a 2-3 sentence reply that leads with resolution and data status.","tips":["What they fear most is data loss — address it in sentence one.","Apology lands better after the facts, not instead of them.","Offer a follow-up call at the end, not the beginning."],"focus":["clarity","audience"],"placeholder":"The sync failure was resolved at 6 a.m. and your data is fully intact —"},
    {"id":"lead-eng-senior-14","level":"senior","profession":"engineer","title":"The message after the layoffs next door","scenario":"The company announced layoffs in sales and marketing this morning. Engineering is untouched, and you can say so. Your draft to the org opens with three paragraphs of empathy before the sentence everyone is scanning for.","task":"Write the first two sentences of your message to the engineering org.","tips":["Say the thing people are scanning for first: engineering is not affected.","Empathy is real and belongs immediately after the fact, not in front of it.","Do not make anxious people read to the bottom."],"focus":["clarity","audience"],"placeholder":"Engineering is not affected by today's changes."},
    {"id":"lead-eng-senior-15","level":"senior","profession":"engineer","title":"The diligence verdict","scenario":"Corp dev asked you to assess the technology of an acquisition target. Your finding: the product is solid but the platform needs a $5M rebuild within 18 months. Your draft report opens with the team's evaluation methodology.","task":"Write a 2-sentence executive summary that leads with the verdict.","tips":["Verdict plus the one number that changes the deal math.","Methodology goes in an appendix — deal teams want the conclusion.","Say clearly whether this changes your support for the deal."],"focus":["structure","precision"],"placeholder":"The product is sound, but plan on a $5M platform rebuild within 18 months."},
    {"id":"lead-eng-senior-16","level":"senior","profession":"engineer","title":"The VP search update","scenario":"After a four-month search, you want the CEO's sign-off to extend an offer to your VP of Infrastructure finalist this week, before a competing offer lands. Your draft update recaps the entire search funnel first.","task":"Write a 2-sentence update that leads with the recommendation and the time pressure.","tips":["Recommendation and deadline first: extend the offer this week.","The competing offer is your urgency — name it early.","Funnel statistics support the quality of the pick; they follow."],"focus":["clarity","impact"]},
    {"id":"lead-eng-senior-17","level":"senior","profession":"engineer","title":"The postmortem executive summary","scenario":"The full postmortem of last month's four-hour outage runs eleven pages. Executives will read only the summary. The essentials: a configuration change bypassed review, and two specific controls will prevent recurrence.","task":"Write a 2-3 sentence executive summary that leads with cause and prevention.","tips":["Cause in plain language, then the two controls, then the deadline for them.","Eleven pages of detail earn trust only if the summary is honest.","Avoid passive voice — say what happened and what will change."],"focus":["structure","clarity"]},
    {"id":"lead-eng-senior-18","level":"senior","profession":"engineer","title":"The Black Friday question","scenario":"In exec staff, the CEO asks point-blank: \"Will the new checkout be live before Black Friday?\" It will — if the payment provider certifies you by November 1, which you rate as likely. You tend to start answers with the dependencies.","task":"Write the 1-2 sentence spoken answer, verdict first.","tips":["Lead with the answer: yes, with one named condition.","State the condition and its likelihood in the same breath.","Offer the date you will know for certain."],"focus":["clarity","precision"],"placeholder":"Yes — as long as the payment provider certifies us by November 1, which I rate as likely."},
    {"id":"lead-eng-senior-19","level":"senior","profession":"engineer","title":"The sunset decision request","scenario":"You want the executive committee to approve sunsetting the legacy reporting product, which serves 2% of revenue but consumes 15% of engineering capacity. Your draft opens with the product's proud history.","task":"Write an opening sentence that states the decision you are asking for.","tips":["Name the decision and the trade in one sentence: 2% of revenue, 15% of capacity.","Honor the history later — decisions open with the ask.","Make clear what happens to affected customers in the follow-on."],"focus":["structure","impact"],"placeholder":"I'm asking us to sunset the legacy reporting product: it serves 2% of revenue and consumes 15% of engineering capacity."},
    {"id":"lead-eng-senior-20","level":"senior","profession":"engineer","title":"The audit committee note","scenario":"The SOC 2 audit surfaced one finding: access reviews for a legacy admin tool were not performed for two quarters. Remediation completes March 15. Your note to the audit committee currently opens with an overview of your compliance program.","task":"Write a 2-sentence note that leads with the finding and the remediation date.","tips":["Audit committees want the finding, the exposure, and the fix date — in that order.","Program overviews read as deflection when they precede the finding.","Precision on dates builds more confidence than adjectives."],"focus":["clarity","precision"]},
    {"id":"lead-eng-senior-21","level":"senior","profession":"engineer","title":"The weekly CEO update","scenario":"You send the CEO a weekly engineering update. This week's real headline: the enterprise SSO blocker for the $2M Meridian deal is fixed. Your draft opens with routine sprint metrics and buries the deal-unblocking fix in bullet six.","task":"Write the update's opening line, leading with the item the CEO cares about most.","tips":["Rank by what moves the company, not by what happened first.","The CEO carries this news to the board and the sales team — hand it over ready.","Routine metrics can live below the fold."],"focus":["audience","impact"],"placeholder":"The SSO blocker on the $2M Meridian deal is fixed —"},
    {"id":"lead-eng-senior-22","level":"senior","profession":"engineer","title":"The emergency spend ask","scenario":"A database cluster is at 94% capacity and will hit its ceiling in roughly three weeks. You need the CFO to approve $180K in unbudgeted infrastructure now. Your draft explains the capacity-planning model before the ask.","task":"Write a 2-3 sentence message that leads with the ask, the amount, and the deadline.","tips":["Amount, deadline, and consequence of waiting — all in the first two sentences.","The capacity model is evidence; attach it, don't open with it.","Give the CFO a one-word way to say yes."],"focus":["clarity","impact"],"placeholder":"I need $180K in unbudgeted infrastructure spend approved this week —"},
    {"id":"lead-eng-senior-23","level":"senior","profession":"engineer","title":"The appointment announcement","scenario":"You are announcing that Priya Sharma, currently a director, becomes VP of Platform on Monday. Your draft opens with three paragraphs about the platform strategy before naming her.","task":"Write the first two sentences of the announcement, leading with the appointment.","tips":["Name, role, and start date in sentence one.","One sentence on why her — specific, not generic praise.","Strategy context follows the news, briefly."],"focus":["clarity","structure"]},
    {"id":"lead-eng-senior-24","level":"senior","profession":"engineer","title":"The public status update","scenario":"Your platform has been down for 40 minutes and the status page needs an update customers will actually read. Your comms team's draft opens with 'We are aware of reports of intermittent degraded performance affecting a subset of users.'","task":"Rewrite the status update in 1-2 sentences that lead with what customers need to know.","tips":["Say plainly what is down and what you are doing.","Give the next update time — that is what stops the refresh-and-rage cycle.","Hedged corporate phrasing reads as evasion during an outage."],"focus":["clarity","audience"],"placeholder":"Checkout and login are currently down. We are working on it now and will update this page by 2:30 p.m. ET."},
    {"id":"lead-eng-senior-25","level":"senior","profession":"engineer","title":"The change-freeze order","scenario":"You are instituting a production change freeze from December 20 to January 2 across all engineering teams. Your draft message opens with last December's incident statistics before anyone learns a freeze is happening.","task":"Write the first two sentences: the action required, the dates, then the reason.","tips":["Orders lead with the order: what stops, when, for whom.","One sentence of rationale earns compliance; statistics can follow.","Name the exception process up front — it cuts the reply-all questions."],"focus":["clarity","structure"],"placeholder":"Production change freeze: December 20 through January 2, all teams."}
  ],
  "start-with-the-audience": [
    {"id":"audience-eng-senior-01","level":"senior","profession":"engineer","title":"Kubernetes for the CFO","scenario":"You are proposing a container-platform migration and the CFO is the approver. Your draft leads with control planes, autoscaling, and cluster federation. The CFO cares about cost, risk, and what breaks if it goes wrong.","task":"Rewrite the proposal's opening 2-3 sentences in the CFO's terms: cost, risk, payback.","tips":["Translate the technology into the three things a CFO prices: spend, risk, timing.","Every technical noun should be replaced or immediately explained by its financial consequence.","Name the payback period — that is the sentence the CFO is looking for."],"focus":["audience","clarity"],"placeholder":"This migration cuts our infrastructure cost about 30% and pays for itself in 14 months."},
    {"id":"audience-eng-senior-02","level":"senior","profession":"engineer","title":"The AI slide for the board","scenario":"You are presenting the AI investment plan to the board. Your current slide describes model fine-tuning, retrieval pipelines, and evaluation harnesses. The board wants to know whether the company is ahead of or behind competitors, and what the bet costs.","task":"Write the 2-3 sentence board narrative for the slide, framed around competitive position and cost.","tips":["Boards think in position, risk, and capital — anchor on where you stand versus rivals.","One plainly stated bet beats five architecture terms.","Keep exactly one technical concept, explained in a clause."],"focus":["audience","impact"]},
    {"id":"audience-eng-senior-03","level":"senior","profession":"engineer","title":"Tech debt without the word 'refactor'","scenario":"You are explaining to the CEO why feature delivery has slowed. The real cause is accumulated shortcuts in the order system. Your draft uses 'refactoring,' 'coupling,' and 'test coverage' — words that mean nothing to a CEO who came up through sales.","task":"Explain the slowdown in 2-3 sentences using only business consequences.","tips":["Describe the effect the CEO already feels: launches take longer, changes break things.","Use a physical analogy only if it carries a decision, not as decoration.","End with what changes if you fix it — in launch-speed terms."],"focus":["audience","clarity"],"placeholder":"Every change to the order system now touches parts built as shortcuts in 2021, so features that took two weeks take six."},
    {"id":"audience-eng-senior-04","level":"senior","profession":"engineer","title":"The customer-facing outage explanation","scenario":"Enterprise customers want to know what caused yesterday's two-hour outage. The truth involves a corrupted etcd quorum during a node upgrade. Customers need honesty and confidence, not your internals.","task":"Write a 3-4 sentence customer explanation: what happened, impact, prevention — no internal jargon.","tips":["Name the failure at the level customers experienced it, not the level you debugged it.","Precision about impact and prevention builds more trust than technical depth.","Read it as their IT director would: does it answer 'can I rely on these people?'"],"focus":["audience","clarity"]},
    {"id":"audience-eng-senior-05","level":"senior","profession":"engineer","title":"Reliability for the sales kickoff","scenario":"You have ten minutes at sales kickoff to talk about platform reliability. Your draft covers SLO methodology and error budgets. The sales team wants one thing: what can they promise customers, and what proof can they show.","task":"Write the 2-3 sentence core message for the sales audience.","tips":["Give sales a sentence they can say verbatim in a customer meeting.","Convert your metrics into the customer's units: minutes of downtime, not nines.","Tell them where the proof lives — the page they can pull up in a demo."],"focus":["audience","impact"],"placeholder":"You can tell any customer: we were up 99.95% last year — under 4.4 hours of downtime — and they can verify it live at status."},
    {"id":"audience-eng-senior-06","level":"senior","profession":"engineer","title":"The architecture decision, translated up","scenario":"Your architecture council chose to split the monolith's billing module into a separate service. You are including it in your exec-staff update. The draft copies the ADR's language: bounded contexts, event sourcing, idempotency.","task":"Rewrite the update in 2 sentences your non-technical peers can act on.","tips":["Executives need to know: what changes for the business, what it costs, what it risks.","If a term needs a definition, it needs a replacement.","Calibrate altitude: this is one line in their week, not a design review."],"focus":["audience","concision"]},
    {"id":"audience-eng-senior-07","level":"senior","profession":"engineer","title":"Why hiring is slow, for the CEO","scenario":"The CEO asks why engineering hiring is behind plan. The honest picture involves pipeline conversion rates, a niche skills market, and one team's high interview bar. Your instinct is to walk through the funnel stage by stage.","task":"Write a 2-3 sentence answer at CEO altitude: the one real constraint and what you are changing.","tips":["Pick the binding constraint — the CEO cannot act on five factors at once.","Funnel data is your evidence, not your answer.","Close with the action and the date it shows results."],"focus":["audience","clarity"],"placeholder":"The bottleneck is one specific skill market — senior payments engineers — where we lose candidates on speed, not money."},
    {"id":"audience-eng-senior-08","level":"senior","profession":"engineer","title":"Error budgets for the audit committee","scenario":"The audit committee asked how engineering decides when reliability work takes priority over features. Your framework is SLOs and error budgets. The committee thinks in controls, thresholds, and escalation paths.","task":"Explain the mechanism in 2-3 sentences using governance language, not SRE language.","tips":["Map your concepts to theirs: an error budget is a threshold that triggers a mandatory response.","Committees want to hear that the control is automatic, not discretionary.","One concrete example of the control firing is worth a page of theory."],"focus":["audience","precision"]},
    {"id":"audience-eng-senior-09","level":"senior","profession":"engineer","title":"The reorg explained to the people in it","scenario":"You are merging two platform teams, and the all-hands draft explains the change in terms of 'organizational efficiency' and 'strategic alignment.' The engineers in the room have one question: what does this mean for me and my work?","task":"Rewrite the core explanation in 3-4 sentences addressed to the engineers affected.","tips":["Answer their actual questions: my manager, my project, my career path.","Corporate abstractions read as concealment to a technical audience.","Say what does not change — that is half of what they need to hear."],"focus":["audience","clarity"]},
    {"id":"audience-eng-senior-10","level":"senior","profession":"engineer","title":"The analyst-call brief","scenario":"The CEO wants you on the investor call to describe your infrastructure advantage. Your draft is accurate but dense: multi-region active-active, sub-100ms p99, 40% unit-cost decline. Analysts need the business meaning in one breath.","task":"Write the 2-sentence version for the call: the advantage in market terms, one proof point.","tips":["Analysts translate everything into margin, moat, or growth — do it for them.","Keep one number; make it the one that survives being quoted.","Rehearse it aloud: it must land in under 20 seconds."],"focus":["audience","impact"],"placeholder":"Our platform serves customers from the closest of six regions, which is why our unit costs fell 40% while usage doubled."},
    {"id":"audience-eng-senior-11","level":"senior","profession":"engineer","title":"Data retention for the general counsel","scenario":"The general counsel asked what happens to customer data when a contract ends. The real answer spans soft deletes, backup rotation, and a 35-day purge cycle. She needs to make contractual commitments on it.","task":"Write a 3-sentence explanation the GC can safely put in contract language.","tips":["Her stake is commitments: what can she promise, with what exceptions.","State the outer bound plainly — 'fully purged within 35 days' — then the one exception.","Flag anything you would not want warranted in a contract."],"focus":["audience","precision"]},
    {"id":"audience-eng-senior-12","level":"senior","profession":"engineer","title":"The vendor outage and the CMO's campaign","scenario":"Your email provider is down and the CMO's product-launch campaign is scheduled to send in three hours. She does not know what an email service provider outage means for her send. Your draft explains the vendor's incident in technical detail.","task":"Write a 2-3 sentence message to the CMO framed around her campaign decision.","tips":["Her question is: send, delay, or reroute — give her the decision framing.","Translate vendor status into her timeline: what must be true by when.","Offer the fallback in her terms, with its cost."],"focus":["audience","clarity"],"placeholder":"Your 2 p.m. send is at risk: our email vendor is down and their fix estimate is 4 p.m."},
    {"id":"audience-eng-senior-13","level":"senior","profession":"engineer","title":"The board email that assumes too much","scenario":"Your draft to the board references 'the Phoenix cutover,' 'the Q2 SEV1,' and 'the Atlas deprecation' — internal shorthand no board member tracks. Each reference needs a bridge or a cut.","task":"Rewrite one of these references as a full sentence a board member can parse cold.","tips":["The curse of knowledge is strongest in recurring updates — assume zero memory of past codenames.","Every internal name gets replaced by what it is and why it matters.","If the bridge takes more than a clause, the item may not belong in a board email."],"focus":["audience","clarity"]},
    {"id":"audience-eng-senior-14","level":"senior","profession":"engineer","title":"One message, two audiences","scenario":"The launch is slipping six weeks. The CEO needs the business impact and the recovery plan; the engineering org needs to know the plan is realistic and nobody is being blamed. You are tempted to write one message for both.","task":"Choose the CEO as primary and write the 2-3 sentence version for her; note in one sentence what the org version changes.","tips":["A message aimed at everyone lands with no one — pick the primary reader.","The CEO version leads with impact and recovery; the org version leads with realism and ownership.","The facts stay identical across versions; only the emphasis moves."],"focus":["audience","structure"]},
    {"id":"audience-eng-senior-15","level":"senior","profession":"engineer","title":"Briefing the new board member","scenario":"A new board member — a retail CEO with no technology background — asked for a 30-minute engineering overview. Your existing deck was built for technical diligence and opens with an architecture diagram.","task":"Write the 2-3 sentence opening of the briefing, pitched to a smart non-technical operator.","tips":["Open with what engineering is for at this company, not what it is made of.","Choose the three things she will actually be asked to govern: spend, risk, capacity.","Let her questions pull you deeper — do not front-load depth."],"focus":["audience","structure"],"placeholder":"Engineering here is 140 people and about a third of operating spend; my job today is to show you what that buys."},
    {"id":"audience-eng-senior-16","level":"senior","profession":"engineer","title":"Build-vs-buy in the CFO's frame","scenario":"Your team wants to build an in-house feature-flag system, and the engineering case is elegant. The CFO will approve or reject on total cost of ownership. Your draft argues technical superiority for three paragraphs.","task":"Rewrite the core argument in 2-3 sentences framed on five-year cost and risk.","tips":["The CFO's frame is TCO: build cost, run cost, opportunity cost of the engineers.","Technical elegance only matters if it changes a number — say which one.","State the vendor option's price as the baseline you are beating or not."],"focus":["audience","precision"]},
    {"id":"audience-eng-senior-17","level":"senior","profession":"engineer","title":"Zero-downtime deploys for the COO","scenario":"You want the COO to fund deployment-pipeline work. Your draft says 'zero-downtime deploys with automated canary analysis.' The COO runs support and fulfillment and thinks in tickets, refunds, and staffing.","task":"Write 2 sentences that translate the investment into the COO's operational metrics.","tips":["Find the line in her P&L that your work moves: support tickets per release, refund volume.","Her nightmare is release-day chaos in the support queue — speak to it.","Give the before/after in her units."],"focus":["audience","impact"],"placeholder":"Every release currently spikes support tickets about 20% for two days; this work makes releases invisible to your queue."},
    {"id":"audience-eng-senior-18","level":"senior","profession":"engineer","title":"The customer QBR for a CIO","scenario":"You are presenting at the quarterly review with your largest customer's CIO. Your draft is your internal QBR reheated: your roadmap, your metrics, your wins. The CIO's stake is her own commitments to her business.","task":"Rewrite the opening 2 sentences around her outcomes, not your output.","tips":["Start from what she promised her company and show how you carried it.","Your roadmap matters only where it touches her plans — cut the rest.","One metric in her business's terms beats five in yours."],"focus":["audience","impact"]},
    {"id":"audience-eng-senior-19","level":"senior","profession":"engineer","title":"The phishing memo everyone must read","scenario":"After a credential-phishing attempt targeted your finance team, you are writing a company-wide security note. Your security lead's draft uses 'adversary-in-the-middle,' 'session token theft,' and 'MFA fatigue.'","task":"Rewrite the core warning in 2-3 sentences every employee can act on.","tips":["The whole company is the audience — write for the least technical reader.","One behavior change, stated as a rule, beats a threat taxonomy.","Tell people exactly what to do when unsure, in one step."],"focus":["audience","clarity"],"placeholder":"Someone is sending fake login pages to our staff. If any login screen appears after you click an email link, stop and report it —"},
    {"id":"audience-eng-senior-20","level":"senior","profession":"engineer","title":"The deprecation notice, two altitudes","scenario":"You are deprecating an API version that a top-10 customer still uses. Their engineers need endpoints and dates; their VP needs to know why this is happening and what it costs them. One email is going to both.","task":"Write the 2-3 sentence opening that serves the VP, with the technical detail signposted below.","tips":["Lead at the altitude of the most senior reader; stack detail beneath for the others.","The VP's questions: why, what breaks, what will this cost my team.","Signpost explicitly: 'Migration details for your engineering team follow.'"],"focus":["audience","structure"]},
    {"id":"audience-eng-senior-21","level":"senior","profession":"engineer","title":"The roadmap slide full of codenames","scenario":"Your board-deck roadmap slide lists Project Falcon, Atlas 2.0, and the Kraken rewrite. To the board these are noise. Each line needs to say what the company gets and when.","task":"Rewrite one roadmap line as a board-readable commitment: outcome, customer, date.","tips":["Codenames are for people in the room every day — boards are not.","The formula: what ships, who it serves, when, and what it unlocks.","If you cannot state the outcome plainly, the board will assume there isn't one."],"focus":["audience","precision"],"placeholder":"Q3: new checkout ships to all enterprise customers — removes our biggest source of cart abandonment."},
    {"id":"audience-eng-senior-22","level":"senior","profession":"engineer","title":"Productivity metrics for a skeptical CFO","scenario":"The CFO questions whether 140 engineers are producing enough and asks how you measure it. Your dashboard has deployment frequency, lead time, and change-failure rate. She suspects these are engineering vanity metrics.","task":"Write a 2-3 sentence answer connecting one engineering metric to a business outcome she trusts.","tips":["Pick the metric with the cleanest line to revenue or cost, and walk that line explicitly.","Concede what the metrics cannot prove — it buys credibility for what they can.","Offer the comparison she is really asking for: are we normal for our size?"],"focus":["audience","precision"]},
    {"id":"audience-eng-senior-23","level":"senior","profession":"engineer","title":"The target's tech risk, for corp dev","scenario":"You assessed an acquisition target and found their single-region deployment and untested backups are the real risks. The corp-dev lead reading your note is financially fluent but not technical, and will paste your words into the deal memo.","task":"Write the 2-3 sentence risk summary in language that survives the paste.","tips":["Write the sentence you want quoted — corp dev will not translate, they will copy.","Express each risk as scenario and cost: what happens, how likely, what it costs to fix.","Avoid words that need your presence to explain."],"focus":["audience","precision"],"placeholder":"If their one data center fails, the product is fully down with no tested recovery — a fix costs roughly $2M and six months."},
    {"id":"audience-eng-senior-24","level":"senior","profession":"engineer","title":"The first briefing for a sales-side CEO","scenario":"Your new CEO came up through enterprise sales and has asked for a first one-on-one about engineering. Your predecessor buried the last CEO in dashboards. You get 30 minutes to establish how the two of you will talk about technology.","task":"Write the 2-3 sentence framing you will open with.","tips":["Offer a contract for the relationship: what you will always tell him, in what terms.","Anchor on what he sells: reliability, speed to market, and cost as sales weapons.","Invite his frame — ask what he needs to never be surprised by."],"focus":["audience","structure"]},
    {"id":"audience-eng-senior-25","level":"senior","profession":"engineer","title":"The pitch to the VP candidate","scenario":"You are closing a VP of Engineering candidate who has three offers. Your draft pitch lists your tech stack and funding round. What senior candidates actually weigh: the problems they will own, the authority they get, and who they work for.","task":"Write a 3-sentence pitch aimed at what a senior candidate actually decides on.","tips":["Senior people buy scope and trust, not stacks — name what she will own outright.","Be specific about the hard problem; vagueness reads as a role not yet real.","Say why her, specifically — generic pitches lose to specific ones."],"focus":["audience","impact"]}
  ],
  "structure-that-carries": [
    {"id":"structure-eng-senior-01","level":"senior","profession":"engineer","title":"One governing idea for the platform deck","scenario":"Your board deck on platform strategy has 22 slides and no single thesis. A director could not say afterward what you were arguing. Everything you want — consolidation funding, two hires, a vendor exit — actually serves one idea.","task":"Write the one governing sentence the whole deck argues, plus its three supporting buckets as short phrases.","tips":["If the deck has no sentence at the top of the pyramid, it is a tour, not an argument.","Every slide must serve one of at most three buckets — or be cut.","Test: could a director repeat your thesis to the CEO in the elevator?"],"focus":["structure","clarity"],"placeholder":"One platform instead of three cuts our run cost 25% and doubles release speed. Buckets: consolidate, staff, exit."},
    {"id":"structure-eng-senior-02","level":"senior","profession":"engineer","title":"SCQA for the tech-debt memo","scenario":"You are opening an investment memo asking for two quarters of focused debt paydown in the order system. You have the facts but no frame: the system works today, incidents are rising, and the CFO thinks debt paydown is a euphemism for slack.","task":"Write the memo's opening as four SCQA sentences: Situation, Complication, Question, Answer.","tips":["Situation is what everyone agrees on; Complication is the change that forces the question.","The Question should be the one the CFO is already asking silently.","Your Answer sentence is the whole memo in miniature — write it last, place it fourth."],"focus":["structure","clarity"]},
    {"id":"structure-eng-senior-03","level":"senior","profession":"engineer","title":"PREP under fire in exec staff","scenario":"In exec staff, the CEO asks: \"Why does everything in engineering take so long?\" You have 45 seconds before someone else fills the silence. PREP — Point, Reason, Example, Point — is the frame that keeps you coherent.","task":"Write your spoken PREP answer in 4 sentences.","tips":["Point first, even under provocation: name the real cause in one sentence.","One vivid example beats three abstract reasons.","Returning to the point at the end is what makes it land as an answer, not a defense."],"focus":["structure","clarity"],"placeholder":"Point: it's not speed, it's queueing — we run too many projects at once."},
    {"id":"structure-eng-senior-04","level":"senior","profession":"engineer","title":"Twelve initiatives, three themes","scenario":"Your QBR draft lists twelve engineering initiatives in the order teams submitted them: a search rewrite, SOC 2 work, the mobile refresh, database upgrades, and eight more. The CFO will see a shopping list, not a strategy.","task":"Group the twelve into three named themes and write the one-line label for each.","tips":["Group by the business outcome served, not by which team does the work.","Theme labels should be claims ('Make the platform cheap to run'), not categories ('Infrastructure').","Anything that fits no theme is a candidate for cutting — say so."],"focus":["structure","clarity"]},
    {"id":"structure-eng-senior-05","level":"senior","profession":"engineer","title":"The incident review execs will read","scenario":"Your postmortem template starts with a timeline, then logs, then contributing factors, with impact and prevention at the end. Executives read it in the wrong order or not at all.","task":"Write the section-heading skeleton (4-5 headings, one line each) for an exec-facing incident review.","tips":["Order by reader priority: impact, cause, prevention, then the timeline for those who want it.","Each heading should be a statement, not a label — 'One config change bypassed review' beats 'Root cause.'","The reader should get the whole story from headings alone."],"focus":["structure","audience"]},
    {"id":"structure-eng-senior-06","level":"senior","profession":"engineer","title":"The build-vs-buy skeleton","scenario":"You are structuring the billing-platform recommendation memo for the CFO and CEO. You have 30 pages of evaluation notes and one page to argue in. The memo needs a shape before it needs sentences.","task":"Write the memo's outline: the governing recommendation plus three supporting sections with one-line summaries.","tips":["The recommendation is the roof; cost, risk, and speed are the classic pillars.","Each pillar gets a claim with a number, not a topic name.","The strongest counterargument gets a section — inside your structure, on your terms."],"focus":["structure","precision"],"placeholder":"Buy. Pillars: 3x cheaper over five years; live in one quarter not four; vendor carries compliance risk."},
    {"id":"structure-eng-senior-07","level":"senior","profession":"engineer","title":"Forty slides into three points","scenario":"Your architecture council produced a 40-slide review of the proposed event-streaming platform. The CEO asked what it concluded. You have one Slack message to convey what matters.","task":"Write a 3-4 sentence summary: the conclusion, then the three points that carry it.","tips":["Start from the decision the 40 slides support, then choose only points that bear its weight.","Three points, one sentence each — resist merging two points into one compound sentence.","Link to the deck for the two people who will read it."],"focus":["structure","concision"]},
    {"id":"structure-eng-senior-08","level":"senior","profession":"engineer","title":"The org announcement in three moves","scenario":"You are announcing that mobile engineering moves under the platform VP and two directors swap scopes. Announcements like this fail when what, why, and when arrive tangled together and people fill gaps with fear.","task":"Write the announcement in three labeled parts — What changes, Why now, What happens next — one to two sentences each.","tips":["Keep the three parts strictly separated; mixing why into what reads as spin.","'What happens next' must include a date and a named owner for questions.","Say explicitly what does not change — reporting lines people feared losing."],"focus":["structure","clarity"]},
    {"id":"structure-eng-senior-09","level":"senior","profession":"engineer","title":"SCQA after the near-miss","scenario":"A contractor's leaked credential nearly exposed customer data last month; it was caught in hours. You are asking the executive committee for $1.2M in security investment, and the room's mood is 'nothing actually happened.'","task":"Write the SCQA opening (4 sentences) that turns the near-miss into the complication.","tips":["The near-miss is your Complication: the world changed, the controls did not.","Pre-empt 'nothing happened' inside the Situation: we were lucky, and here is why it was luck.","The Question should make inaction a decision, not a default."],"focus":["structure","impact"]},
    {"id":"structure-eng-senior-10","level":"senior","profession":"engineer","title":"Five teams, one hiring case","scenario":"Five of your directors each sent you separate hiring asks totaling 19 heads, each argued from their team's pain. Forwarded as-is to the CFO, they read as five lobbyists. You need one structured case.","task":"Write the governing sentence of the combined case and the 2-3 buckets you would group the 19 roles into.","tips":["Group roles by company outcome (revenue protection, new product, risk) — never by team.","The governing sentence should trade in the CFO's currency: what the 19 heads buy.","Be willing to cut roles that fit no bucket; a coherent 15 beats a padded 19."],"focus":["structure","audience"],"placeholder":"These 19 roles buy three things: the payments launch, enterprise reliability, and closing our security gap."},
    {"id":"structure-eng-senior-11","level":"senior","profession":"engineer","title":"PREP for the AI board question","scenario":"A board member will likely ask: \"Are we falling behind on AI?\" You have a real answer — deliberate focus on two applied bets rather than a research program — but in past meetings you have rambled through it.","task":"Write the PREP answer in 4 sentences you could deliver in 30 seconds.","tips":["The Point is a position, not a mood: 'No — we are concentrated, not behind.'","Your Example should be one shipped thing with a number attached.","Practice the return to the point; it is what stops the follow-up spiral."],"focus":["structure","impact"]},
    {"id":"structure-eng-senior-12","level":"senior","profession":"engineer","title":"The negotiation opener with a spine","scenario":"You are opening a renewal negotiation with your cloud provider's enterprise team. Your position: three-year commit in exchange for 28% off and better support terms. Your draft email meanders through relationship pleasantries into vague intent.","task":"Structure the opening message in 3 sentences: position, rationale, next step.","tips":["State the shape of the deal you want in sentence one — anchoring is structure.","One sentence of rationale shows the number is reasoned, not plucked.","End with a concrete next step and date; open loops stall negotiations."],"focus":["structure","clarity"]},
    {"id":"structure-eng-senior-13","level":"senior","profession":"engineer","title":"The annual strategy's single spine","scenario":"Your annual engineering strategy doc has grown to nine priorities, because every director's favorite made the list. Nine priorities means none. The exercise: force the pyramid.","task":"Write the strategy's single governing idea and at most three priorities beneath it, one line each.","tips":["The governing idea should make some things clearly not priorities — that is its job.","If two priorities always travel together, they are one priority.","Each priority line: verb, object, measurable outcome."],"focus":["structure","clarity"],"placeholder":"This year we make the platform boring: reliable, cheap, and fast to build on."},
    {"id":"structure-eng-senior-14","level":"senior","profession":"engineer","title":"Restructure before you forward","scenario":"A director sent you a long, passionate email about database problems that genuinely needs the CEO's attention. It has the facts, but they arrive in discovery order: how she found it, then history, then severity. You will forward it with a framing note.","task":"Write the 3-sentence framing note that gives the CEO the structure the email lacks.","tips":["Your note is the pyramid; her email becomes the appendix.","Sentence one: what this is and what decision it needs. Then the two facts that matter.","Never forward raw discovery-order prose to a CEO without a roof on it."],"focus":["structure","concision"]},
    {"id":"structure-eng-senior-15","level":"senior","profession":"engineer","title":"The apology letter's load-bearing order","scenario":"You are writing the customer letter after last week's four-hour outage. Drafts keep dissolving into a soup of apology, explanation, and promises. The letter needs a fixed order: acknowledgment, impact, cause, prevention, recompense.","task":"Write one sentence for each of the five parts, in that order.","tips":["Each part does one job; when a sentence tries to apologize and explain at once, both fail.","Impact comes before cause — customers care what happened to them before why.","The prevention sentence needs a date, or it reads as sentiment."],"focus":["structure","audience"]},
    {"id":"structure-eng-senior-16","level":"senior","profession":"engineer","title":"The QBR arc: results, drivers, asks","scenario":"Your QBR materials are a pile of charts in no order. The narrative that works for a CEO/CFO audience is an arc: what happened, why it happened, what you need next quarter. Right now your asks are scattered across slides 4, 11, and 17.","task":"Write the one-line summary for each act: Results, Drivers, Asks.","tips":["All asks live together in act three — scattered asks all get deferred.","Drivers explain results; if a driver explains nothing on the results slide, cut it.","Write the three lines first, then let the charts audition for slots."],"focus":["structure","impact"]},
    {"id":"structure-eng-senior-17","level":"senior","profession":"engineer","title":"Nine risks, three shelves","scenario":"Your diligence report on the acquisition target lists nine technical risks in the order your team found them: no staging environment, key-person dependency, expired certs, untested backups, and five more. The deal team needs shape, not a list.","task":"Group the nine risks into three named categories and write a one-line summary for each category.","tips":["Categories should sort by what the deal team does about them: price it, fix it, walk away.","Name each category by its consequence, not its technology.","The category summary carries the category — a reader skipping details still gets the risk."],"focus":["structure","precision"]},
    {"id":"structure-eng-senior-18","level":"senior","profession":"engineer","title":"The all-hands in three movements","scenario":"Your quarterly engineering all-hands script is a flat sequence of 14 updates. People leave remembering nothing. You want three movements: where we are, what we learned, where we go — with every update slotted or cut.","task":"Write the one-sentence thesis of each movement.","tips":["A talk with three movements survives being half-remembered; 14 updates do not.","Each movement's thesis should be sayable without slides.","Updates that fit no movement go to the written notes, not the talk."],"focus":["structure","audience"],"placeholder":"Movement 1: we shipped what we promised, and the platform held."},
    {"id":"structure-eng-senior-19","level":"senior","profession":"engineer","title":"SCQA for platform consolidation","scenario":"You want the exec committee to approve consolidating three overlapping internal platforms into one. Everyone knows the three platforms exist; nobody has framed why now — two of the three lose their lead engineers this year.","task":"Write the four SCQA sentences for the consolidation pitch.","tips":["The Complication is the departures — a stable status quo just stopped being stable.","Keep the Situation to one sentence; the room already lives in it.","Your Answer names the surviving platform and the migration bound: what, by when, for how much."],"focus":["structure","clarity"]},
    {"id":"structure-eng-senior-20","level":"senior","profession":"engineer","title":"The state-of-engineering doc","scenario":"The CEO asked for a 'state of engineering' document for the new fiscal year — the kind of doc that gets forwarded to the board. You have material on delivery, reliability, cost, people, and risk, and no organizing principle.","task":"Write the doc's governing thesis sentence and its 3 top-level sections with one-line claims.","tips":["A state-of doc still needs a verdict — 'healthy, with two named risks' is a structure.","Sections carry claims, not topics: 'Delivery is fast but concentrated in two teams.'","Write the thesis so the board could quote it verbatim."],"focus":["structure","clarity"]},
    {"id":"structure-eng-senior-21","level":"senior","profession":"engineer","title":"PREP when the CFO interrupts","scenario":"Mid-QBR, the CFO cuts in: \"Cloud costs are up 22% and I haven't heard why.\" Your data is three slides ahead. You need a structured spoken answer now, not a plea to wait for slide 14.","task":"Write your 4-sentence PREP answer, delivered on the spot.","tips":["Answer now, in PREP order; never ask an interrupting CFO to wait for a later slide.","Point: costs are up 22% because usage grew 40% — unit cost actually fell.","Your Example is the one workload that explains most of the delta."],"focus":["structure","precision"],"placeholder":"Costs rose 22% because usage grew 40% — per-customer cost is actually down."},
    {"id":"structure-eng-senior-22","level":"senior","profession":"engineer","title":"The RFP response's executive summary","scenario":"Your team wrote a strong 30-page response to an enterprise prospect's technical RFP. The buying committee's executives will read only the first page. That page currently summarizes the document's sections instead of making the case.","task":"Write the executive summary as a 4-sentence pyramid: the claim, then three proof points.","tips":["Summarize the argument, not the table of contents.","The claim answers their question: why is this the lowest-risk choice?","Each proof point should map to a section, so technical readers can drill down."],"focus":["structure","audience"]},
    {"id":"structure-eng-senior-23","level":"senior","profession":"engineer","title":"The exception to the hiring freeze","scenario":"There is a company hiring freeze, and you need one exception: a staff database engineer, because the sole expert on your payment store resigns in six weeks. Exception requests die when they read as special pleading rather than structured risk.","task":"Structure the request in 4 sentences: ask, risk, why existing options fail, decision date.","tips":["Quantify the risk window: one person, six weeks, systems that move money.","Pre-empt the obvious alternative — 'train someone internally' — inside your structure.","Give the approver a decision date tied to the departure, not an open-ended plea."],"focus":["structure","impact"]},
    {"id":"structure-eng-senior-24","level":"senior","profession":"engineer","title":"Two minutes for investors","scenario":"The CEO wants you to give investors a two-minute engineering overview during the funding roadshow. Two minutes is roughly 250 words — a governing claim and three supports, nothing else fits.","task":"Write the governing claim and the first sentence of each of the three supports.","tips":["Pick the claim investors fund: the platform scales without proportional headcount.","Three supports: one about cost, one about speed, one about risk — each with a number.","Cut anything you cannot say from memory; scripts die in roadshows."],"focus":["structure","concision"],"placeholder":"Our platform is why revenue can triple while engineering grows 20%."},
    {"id":"structure-eng-senior-25","level":"senior","profession":"engineer","title":"From timeline to causation","scenario":"Your incident channel produced a 90-line timeline of Tuesday's payment outage. The COO asked what actually happened. A timeline is chronology; she is asking for causation: what broke, what it caused, what fixed it, what prevents it.","task":"Convert the timeline into a 4-sentence causal chain: trigger, propagation, resolution, prevention.","tips":["Chronology answers 'when'; executives ask 'why' — restructure around cause and effect.","One sentence per link; resist re-importing timestamps.","The prevention sentence is the one the COO will repeat — make it specific."],"focus":["structure","clarity"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-eng-senior-01","level":"senior","profession":"engineer","title":"The board update that triples its length","scenario":"Your board update runs 900 words because every point carries throat-clearing: 'It is worth noting that,' 'In order to,' 'At this point in time.' A board reads it in the margins of a longer meeting.","task":"Cut the following to under 300 words in spirit — rewrite this bloated sentence to its core: 'It is worth noting that, at this point in time, we have largely completed the majority of the migration work.'","tips":["Strike 'it is worth noting that' — if it weren't worth noting you wouldn't write it.","'At this point in time' is 'now'; 'the majority of' is 'most.'","Hedges like 'largely' next to 'completed' cancel the achievement."],"focus":["concision","clarity"],"placeholder":"The migration is nearly complete."},
    {"id":"concise-eng-senior-02","level":"senior","profession":"engineer","title":"The nominalized status report","scenario":"Your weekly to the CEO is full of nominalizations: 'We performed a remediation of the issue,' 'The team made a decision to prioritize.' Buried verbs make strong actions sound bureaucratic.","task":"Rewrite these two sentences with live verbs, in one tight sentence.","tips":["'Performed a remediation of' is just 'fixed.'","'Made a decision to prioritize' is 'prioritized.'","Verbs carry energy; nouns bury it."],"focus":["concision","clarity"],"placeholder":"We fixed the issue and prioritized the payments work."},
    {"id":"concise-eng-senior-03","level":"senior","profession":"engineer","title":"The meta-commentary in the incident note","scenario":"Your incident summary opens with 'I wanted to take a moment to reach out and provide some context around what happened.' The exec team wants the incident, not the preamble about providing the incident.","task":"Delete the meta-commentary and write the real first sentence of the summary.","tips":["'I wanted to reach out to provide context' says nothing — just provide it.","Announcing that you are about to inform someone wastes their first read.","Start with the fact, not the frame around the fact."],"focus":["concision","clarity"]},
    {"id":"concise-eng-senior-04","level":"senior","profession":"engineer","title":"Redundant pairs in the strategy doc","scenario":"Your platform strategy doc leans on doubled phrases: 'each and every,' 'first and foremost,' 'plan and prepare,' 'clear and simple.' At exec length they add pages and subtract force.","task":"Rewrite this sentence without the redundant pairs: 'First and foremost, we must plan and prepare for each and every failure scenario in a clear and simple way.'","tips":["Pick the stronger word in each pair and drop the other.","Doubled synonyms signal padding, not emphasis.","One precise word outperforms two vague ones."],"focus":["concision","clarity"],"placeholder":"First, we plan for every failure scenario, simply."},
    {"id":"concise-eng-senior-05","level":"senior","profession":"engineer","title":"Halve the tech-debt paragraph","scenario":"A paragraph in your investment memo runs 140 words to say the legacy system causes most incidents and slows delivery. The CFO gives each paragraph ten seconds.","task":"Compress this into two sentences: 'Over the years, largely due to a series of decisions that made sense at the time under the constraints we faced, the legacy order system has gradually accumulated a significant amount of technical debt, which has, over time, come to be responsible for a substantial proportion of the incidents we experience, while also having the effect of slowing down our ability to deliver new features to customers.'","tips":["Find the two facts — most incidents, slower delivery — and state them.","Backstory about 'decisions that made sense at the time' can go entirely.","Every 'gradually,' 'substantial,' 'significant' is a word doing no work."],"focus":["concision","impact"],"placeholder":"The legacy order system causes 60% of our incidents and doubles feature timelines."},
    {"id":"concise-eng-senior-06","level":"senior","profession":"engineer","title":"The hedged recommendation","scenario":"Your build-vs-buy memo recommends buying, but the sentence reads: 'It might perhaps be worth considering the possibility that buying could potentially be the better option.' Five hedges bury one decision.","task":"Rewrite it as a single clean recommendation.","tips":["Count the hedges: might, perhaps, worth considering, could, potentially — cut all five.","A recommendation the reader has to excavate is not a recommendation.","'We should buy' is a sentence; the rest was apology."],"focus":["concision","impact"],"placeholder":"We should buy."},
    {"id":"concise-eng-senior-07","level":"senior","profession":"engineer","title":"The Slack update nobody finishes","scenario":"Your #exec Slack update on the launch runs eight dense sentences of filler before the one fact that matters: the launch date holds. Exec Slack messages are read in three seconds or not at all.","task":"Write the three-second version — one sentence, the fact that matters.","tips":["In chat, the first line is the whole message — put the fact there.","If it needs a second sentence, it needs a doc, not a Slack.","Cut every clause that isn't the date holding."],"focus":["concision","clarity"],"placeholder":"Launch date holds: March 4, on track."},
    {"id":"concise-eng-senior-08","level":"senior","profession":"engineer","title":"The filler openers in the QBR script","scenario":"Your QBR script begins nearly every point with 'So basically,' 'What I would say is,' or 'The way I think about it is.' Spoken aloud to the CEO and CFO, these verbal on-ramps drain authority.","task":"Rewrite this spoken line without the on-ramp: 'So basically, what I would say is that the way I think about reliability is that it's fundamentally about trust.'","tips":["'So basically what I would say is' delays your actual claim by eight words.","Executives read the on-ramp as hesitation, not warmth.","Start on the claim: 'Reliability is trust.'"],"focus":["concision","impact"],"placeholder":"Reliability is trust."},
    {"id":"concise-eng-senior-09","level":"senior","profession":"engineer","title":"The over-qualified risk statement","scenario":"Your diligence report says: 'There is a potential possibility that, under certain circumstances which may or may not occur, the single-region setup could conceivably lead to some degree of downtime.' The deal team needs a risk, not a fog.","task":"State the risk in one plain sentence.","tips":["Stacked qualifiers signal you are afraid to commit to the risk — commit.","'Potential possibility' is one word: risk.","Name the failure and its likelihood, not a cloud of maybes."],"focus":["concision","precision"],"placeholder":"If their single region fails, the product goes fully down — and it will fail eventually."},
    {"id":"concise-eng-senior-10","level":"senior","profession":"engineer","title":"The apology that over-explains","scenario":"Your customer outage letter spends 200 words explaining the technical cause in loving detail before the two sentences customers care about: it's fixed, here's what prevents recurrence. Length reads as defensiveness.","task":"Cut the technical over-explanation and write the two sentences that matter.","tips":["Customers do not want the etcd tutorial — they want fixed and won't-happen-again.","Depth of explanation reads as excuse-making, not transparency.","One line of cause is enough; spend the words on prevention."],"focus":["concision","audience"]},
    {"id":"concise-eng-senior-11","level":"senior","profession":"engineer","title":"The email that says everything twice","scenario":"Your headcount request to the CFO makes each point, then restates it 'to be clear,' then summarizes it again at the end. Three passes at one idea triple the length and halve the trust.","task":"Rewrite this triple-stated point as one sentence: 'We need four engineers. To be clear, the ask is for four additional engineers. In summary, four more engineers are required.'","tips":["Saying it three times signals you don't trust it to land once.","'To be clear' usually precedes a repeat, not a clarification.","State the number once, cleanly, and stop."],"focus":["concision","clarity"],"placeholder":"We need four more engineers."},
    {"id":"concise-eng-senior-12","level":"senior","profession":"engineer","title":"The bloated slide title","scenario":"Your board slide is titled 'Some Considerations and Observations Regarding the Current State and Future Direction of Our Platform Infrastructure Strategy.' A slide title should be a claim, not a category.","task":"Rewrite the title as a claim under eight words.","tips":["A title that lists topics tells the reader nothing they can act on.","Make the title the takeaway: what should they conclude from this slide?","If the title is a claim, the slide just has to prove it."],"focus":["concision","impact"],"placeholder":"One platform, 25% cheaper to run."},
    {"id":"concise-eng-senior-13","level":"senior","profession":"engineer","title":"Cut the caveats from the answer","scenario":"The CEO asked if the SSO fix is done. Your reply: 'Well, it depends somewhat on how you define done, but I think for the most part, subject to final testing, we're basically there.' The CEO hears 'no.'","task":"Answer the question in one clean sentence with the one real caveat, if any.","tips":["A pile of caveats reads as no; one honest caveat reads as yes-with-a-condition.","Decide what 'done' means and answer against it.","If it's done, say done; if not, say the date."],"focus":["concision","precision"],"placeholder":"Done — it ships to production tomorrow after final testing tonight."},
    {"id":"concise-eng-senior-14","level":"senior","profession":"engineer","title":"The org email padded with mission","scenario":"Your reorg announcement wraps the actual change in two paragraphs of mission and values before and after. People skim past the values to find the change, then reread anxiously.","task":"Cut the mission padding and write the lean version: what changes, in two sentences.","tips":["Mission language around an org change reads as cushioning, and people distrust cushions.","State the change; let the values live in how you handle questions, not in the preamble.","Every sentence before the change is a sentence of anxiety you created."],"focus":["concision","audience"]},
    {"id":"concise-eng-senior-15","level":"senior","profession":"engineer","title":"The vendor email's throat-clearing","scenario":"Your negotiation email to the cloud vendor opens: 'I hope this email finds you well. I wanted to reach out to touch base and circle back on our ongoing conversation regarding the renewal.' The buyer with leverage doesn't open soft.","task":"Rewrite the opening as one sentence that states your position.","tips":["'I hope this finds you well / touch base / circle back' is three clichés and zero content.","In a negotiation, the opener sets the anchor — don't waste it on pleasantries.","Lead with the number or the deal shape you want."],"focus":["concision","impact"],"placeholder":"We'll commit to three years for 28% off and next-business-day support."},
    {"id":"concise-eng-senior-16","level":"senior","profession":"engineer","title":"The passive-voice postmortem","scenario":"Your postmortem is written entirely in the passive to soften blame: 'A change was made, a review was bypassed, an alert was not configured.' Passive voice doubles length and hides who does what next.","task":"Rewrite this passive chain in active voice: 'A configuration change was deployed, the review step was skipped, and the resulting alert was not received.'","tips":["Passive voice erases the actor — executives read that as evasion.","Active voice is shorter and assigns clear ownership for the fix.","'The system skipped the review' names the gap without blaming a person."],"focus":["concision","clarity"],"placeholder":"The deploy skipped the review step, so no alert fired."},
    {"id":"concise-eng-senior-17","level":"senior","profession":"engineer","title":"Trim the list of five reasons","scenario":"Your case for the platform investment lists five reasons, but reasons three through five are weak and dilute the two strong ones. More reasons feel thorough but read as padding when some are soft.","task":"Name the two strongest reasons only, in two sentences, and drop the rest.","tips":["A weak reason weakens the strong ones by association — the reader averages them.","Two undeniable points beat five arguable ones.","If you wouldn't defend a reason under questioning, cut it."],"focus":["concision","impact"]},
    {"id":"concise-eng-senior-18","level":"senior","profession":"engineer","title":"The 'in order to' epidemic","scenario":"Your strategy memo uses 'in order to' eleven times. Each is three words where one would do, and together they slow every sentence.","task":"Rewrite this sentence dropping the filler: 'In order to reduce costs, we need to consolidate platforms in order to eliminate redundant infrastructure.'","tips":["'In order to' is almost always just 'to.'","Reading a sentence aloud exposes the drag these add.","Small cuts, repeated across a doc, reclaim a whole page."],"focus":["concision","clarity"],"placeholder":"To cut costs, we'll consolidate platforms and drop redundant infrastructure."},
    {"id":"concise-eng-senior-19","level":"senior","profession":"engineer","title":"The over-context 1:1 prep note","scenario":"You send the CEO a pre-1:1 note. This week's version spends 250 words setting up context she already has before reaching the one decision you need from her.","task":"Cut the shared context and write the note as the decision plus its two options, in three sentences.","tips":["Never re-brief someone on what they already know — it wastes their read and signals you might not know they know.","Open with the decision needed, then the options.","Context she lacks is worth including; context she has is noise."],"focus":["concision","audience"]},
    {"id":"concise-eng-senior-20","level":"senior","profession":"engineer","title":"The adjective-stuffed announcement","scenario":"Your VP appointment announcement calls the new hire 'an incredibly talented, deeply experienced, highly respected, world-class engineering leader.' Four superlatives read as one insecurity.","task":"Rewrite the description with one specific fact instead of four adjectives.","tips":["Stacked superlatives cancel out — the reader discounts all of them.","One concrete accomplishment outweighs four vague praises.","Show the caliber; don't assert it."],"focus":["concision","impact"],"placeholder":"Priya scaled our payments platform through 10x growth over four years."},
    {"id":"concise-eng-senior-21","level":"senior","profession":"engineer","title":"The runaway executive summary","scenario":"Your RFP response's executive summary is 400 words because it summarizes all thirty pages. An executive summary that long is just a second document.","task":"Cut it to a four-sentence version: the claim and three proofs.","tips":["A summary that covers everything emphasizes nothing.","Four sentences force you to choose your three best proofs.","If a sentence doesn't advance the claim, it belongs in the body."],"focus":["concision","structure"]},
    {"id":"concise-eng-senior-22","level":"senior","profession":"engineer","title":"The status page word salad","scenario":"Your status update reads: 'We are currently in the process of actively investigating and working to identify the root cause of the issue that is presently affecting some of our services.' Customers in an outage want plain, short truth.","task":"Rewrite it in one plain sentence.","tips":["'Currently in the process of actively' is four words for 'are.'","During an outage, verbosity reads as spin — be blunt.","Say what's broken and that you're on it, then stop."],"focus":["concision","audience"],"placeholder":"Checkout is down and we're on it — next update at 3:00 p.m. ET."},
    {"id":"concise-eng-senior-23","level":"senior","profession":"engineer","title":"The doubled-up close","scenario":"Your investment memo ends with a summary paragraph, then a 'next steps' paragraph, then a 'to conclude' paragraph — three endings restating the same ask. The reader hits the ask three times and trusts it less each time.","task":"Write a single closing sentence with the ask and the decision date.","tips":["Multiple closings signal you don't trust the memo to have made its case.","One ask, one date, one sentence — then stop.","The best ending is the one the reader doesn't notice as an ending."],"focus":["concision","structure"],"placeholder":"Please approve the $3M by end of quarter so we can start next sprint."},
    {"id":"concise-eng-senior-24","level":"senior","profession":"engineer","title":"The over-narrated demo","scenario":"You are demoing the new reliability dashboard to the board and narrating every click: 'Now I'm going to click here, and then this will load, and you'll see it populate.' The board wants the insight, not the procedure.","task":"Rewrite your narration for one screen as a single sentence stating what it proves.","tips":["Nobody needs the click-by-click — they need the takeaway.","Say what the screen means, not what you're doing to it.","Cut 'now I'm going to' entirely; land on the point."],"focus":["concision","audience"],"placeholder":"This is last quarter's uptime: 99.95%, our best ever."},
    {"id":"concise-eng-senior-25","level":"senior","profession":"engineer","title":"The final polish pass","scenario":"Your board narrative is done and correct at 500 words, but it has one more pass in it. Every 'in terms of,' 'the fact that,' 'a number of,' and 'going forward' is a candidate to cut without losing meaning.","task":"Rewrite this sentence removing all filler: 'In terms of the fact that we have a number of reliability issues, going forward we plan to address them.'","tips":["'In terms of' and 'the fact that' almost never carry meaning.","'A number of' is 'several' or, better, the actual number.","'Going forward' is implied by any plan — cut it."],"focus":["concision","clarity"],"placeholder":"We have three reliability issues and a plan to fix each."}
  ],
  "precision-and-evidence": [
    {"id":"precision-eng-senior-01","level":"senior","profession":"engineer","title":"Numbers instead of 'significantly'","scenario":"Your board update says the migration 'significantly reduced our costs' and 'greatly improved performance.' The board has heard 'significantly' from every function this quarter and it means nothing.","task":"Rewrite the two claims with specific numbers.","tips":["'Significantly' is a placeholder for a number you haven't looked up.","One real figure ('cut run cost 31%') beats any intensifier.","If you don't have the number, that's the work — get it before the claim."],"focus":["precision","impact"],"placeholder":"The migration cut run cost 31% and dropped p99 latency from 400ms to 90ms."},
    {"id":"precision-eng-senior-02","level":"senior","profession":"engineer","title":"'Soon' is not a date","scenario":"The CEO asks when the payments launch ships. Your draft says 'soon,' 'in the near term,' 'shortly.' The CEO needs a date she can repeat to the board.","task":"Replace the vague timing with a specific commitment and its one dependency.","tips":["'Soon' protects you and fails the reader — commit to a date.","A date with a named dependency is honest; a date with none is a lie waiting to happen.","If the date is a range, give the range and the confidence."],"focus":["precision","clarity"],"placeholder":"March 4, contingent on payment-provider certification by February 20 — which I rate 80% likely."},
    {"id":"precision-eng-senior-03","level":"senior","profession":"engineer","title":"From dashboard to one insight","scenario":"Your QBR reliability slide is a wall of twelve metrics. The CFO's eyes glaze. Somewhere in there is one insight: uptime is up but recovery time is your real risk.","task":"Write the one-sentence insight the twelve metrics actually support.","tips":["A dashboard is data; executives pay you for the insight in it.","Ask what one thing you'd want the CFO to remember, and say only that.","The metrics become backup for the insight, not the message."],"focus":["precision","impact"],"placeholder":"We're highly available but slow to recover — mean time to recovery is our biggest exposure."},
    {"id":"precision-eng-senior-04","level":"senior","profession":"engineer","title":"What, so what, now what","scenario":"You are reporting that error rates rose 0.3% last month. Stated alone it's a number without meaning. The exec team needs the What, the So What, and the Now What.","task":"Write the three-part statement: the fact, its consequence, and your action.","tips":["A number with no 'so what' invites the reader to invent one, usually worse.","So-what translates the metric into money, risk, or customer impact.","Now-what shows you own it — the fact plus a plan, not a fact alone."],"focus":["precision","structure"],"placeholder":"Error rates rose 0.3% (What), which cost ~200 failed checkouts a day (So What); we've shipped a fix and expect baseline by Friday (Now What)."},
    {"id":"precision-eng-senior-05","level":"senior","profession":"engineer","title":"Pass the skeptic's test","scenario":"Your platform-investment memo claims consolidation will 'save millions.' A skeptical CFO will ask: over what period, net of what costs, based on what assumptions. The claim has to survive that before you send it.","task":"Rewrite 'save millions' as a claim that survives three skeptical questions.","tips":["Anticipate the CFO's questions and answer them inside the claim.","State the period, the net, and the key assumption.","A claim that can't survive scrutiny shouldn't be in the memo."],"focus":["precision","impact"],"placeholder":"Consolidation saves $4.2M over five years, net of $1.1M migration cost, assuming flat usage growth."},
    {"id":"precision-eng-senior-06","level":"senior","profession":"engineer","title":"The 'most' that hides the number","scenario":"Your tech-debt case says the legacy system causes 'most' of your incidents and 'a lot of' engineering time. You actually have the figures — 60% and roughly 8 engineer-months a year.","task":"Rewrite the claim with the real figures.","tips":["'Most' when you know it's 60% throws away credibility for no reason.","Precise numbers signal you measured; vague ones signal you guessed.","Convert 'a lot of time' into a countable unit: engineer-months, dollars."],"focus":["precision","impact"],"placeholder":"The legacy system causes 60% of our incidents and burns roughly 8 engineer-months a year."},
    {"id":"precision-eng-senior-07","level":"senior","profession":"engineer","title":"Separate the estimate from the fact","scenario":"Your capacity note tells the CFO the database 'will' hit its ceiling in three weeks. In truth, that's a projection with a confidence range, and presenting it as certainty will burn you if it's off.","task":"Restate it distinguishing the measured fact from the projection and its confidence.","tips":["Blurring measured and modeled numbers costs you trust when the model is wrong.","State what you know (current usage) and what you project (ceiling date) separately.","Attach a confidence or range to the projection."],"focus":["precision","clarity"],"placeholder":"We're at 94% now (measured); at current growth we project the ceiling in 18-24 days."},
    {"id":"precision-eng-senior-08","level":"senior","profession":"engineer","title":"Quantify the reliability win for sales","scenario":"Sales wants a reliability number they can quote. Your instinct is 'four nines,' but a customer's CIO thinks in downtime minutes and dollars, not nines.","task":"Convert '99.95% uptime' into the two concrete units a buyer cares about.","tips":["Nines are engineering units; buyers price minutes and money.","99.95% is about 4.4 hours of downtime a year — say that.","Pair the availability with the recovery speed customers actually feel."],"focus":["precision","audience"],"placeholder":"99.95% uptime means under 4.4 hours of downtime a year, and we recover from incidents in under 15 minutes on average."},
    {"id":"precision-eng-senior-09","level":"senior","profession":"engineer","title":"The evidence behind 'ahead of competitors'","scenario":"Your board AI slide claims you're 'ahead of competitors.' A director will ask on what basis. You need a specific, defensible proof point, not a vibe.","task":"Replace the claim with one that names the evidence.","tips":["'Ahead of competitors' with no evidence invites the exact question you can't answer.","Anchor on something measurable: a capability shipped, a metric, a customer count.","If you can't evidence it, soften the claim to what you can defend."],"focus":["precision","impact"]},
    {"id":"precision-eng-senior-10","level":"senior","profession":"engineer","title":"The vendor claim you can't yet verify","scenario":"The billing vendor promises '99.99% uptime and 50ms latency.' Your memo repeats these as facts. But you haven't tested them, and staking a CFO recommendation on unverified vendor marketing is a trap.","task":"Rewrite the memo line to distinguish the vendor's claim from your verified evidence.","tips":["A vendor's number is a claim until you've measured it — label it as theirs.","Say what you've independently verified versus what you're taking on trust.","Note how you'll validate before committing."],"focus":["precision","clarity"],"placeholder":"The vendor claims 99.99% uptime; our reference calls confirmed 99.97% in practice, which we'll verify in a paid pilot."},
    {"id":"precision-eng-senior-11","level":"senior","profession":"engineer","title":"'Improved' needs a baseline","scenario":"Your update says deploy frequency 'improved' this quarter. Improved from what, to what? Without a baseline, 'improved' is unfalsifiable and therefore worthless to the CEO.","task":"Rewrite the claim with a before and an after number.","tips":["'Improved' with no baseline can't be trusted or challenged — give both endpoints.","From-X-to-Y is the honest form of any progress claim.","If the baseline is embarrassing, the delta is the good news — show it."],"focus":["precision","impact"],"placeholder":"Deploy frequency went from twice a week to daily this quarter."},
    {"id":"precision-eng-senior-12","level":"senior","profession":"engineer","title":"The risk stated as a probability","scenario":"Your diligence report says the target 'could' have a scaling problem. Corp dev needs to price the risk, and 'could' spans everything from 5% to 95%. You have a view — give it.","task":"Restate the risk with your estimated likelihood and the cost if it hits.","tips":["'Could' is uninformative; a probability, even rough, lets the deal team price it.","Pair likelihood with impact — a likely small problem differs from an unlikely huge one.","Own the estimate; that's what your expertise is for."],"focus":["precision","impact"],"placeholder":"I'd put ~70% odds they hit a scaling wall within 18 months, costing roughly $2M to fix."},
    {"id":"precision-eng-senior-13","level":"senior","profession":"engineer","title":"Cost per unit, not total spend","scenario":"The CFO sees cloud spend up 22% and worries. The precise story is that spend rose 22% while usage rose 40%, so unit cost fell. Total spend alone tells the wrong story.","task":"State the cost story in the unit that reflects efficiency, in two sentences.","tips":["Absolute spend can rise while efficiency improves — say both.","Cost-per-customer or cost-per-transaction is the number that reflects your work.","Lead with the reassuring truth: unit cost is down."],"focus":["precision","audience"],"placeholder":"Spend rose 22%, but usage rose 40% — so our cost per transaction actually fell 13%."},
    {"id":"precision-eng-senior-14","level":"senior","profession":"engineer","title":"The postmortem's precise impact","scenario":"Your outage postmortem says the incident 'affected some customers for a while.' The exec team needs the exact blast radius: how many, which tier, how long, what they experienced.","task":"Rewrite the impact line with specific figures.","tips":["'Some customers for a while' is the sentence executives distrust most.","Quantify: percent affected, which segment, duration, what failed for them.","Precision here is what earns trust for the prevention plan later."],"focus":["precision","clarity"],"placeholder":"For 47 minutes, ~3% of transactions failed — about 1,200 checkouts, concentrated in enterprise accounts."},
    {"id":"precision-eng-senior-15","level":"senior","profession":"engineer","title":"The ROI the CFO can check","scenario":"Your deployment-pipeline funding request claims 'strong ROI.' The CFO will build her own model; give her the inputs, not the conclusion. Vague ROI reads as sales, not analysis.","task":"State the ROI as inputs the CFO can verify: cost, benefit, and time to break even.","tips":["'Strong ROI' asks the CFO to trust; showing the math lets her verify.","Give the cost, the annual benefit, and the payback period.","Name your key assumption so she can stress-test it, not catch it later."],"focus":["precision","impact"],"placeholder":"$400K one-time; saves ~$300K/year in reduced release incidents; breaks even in 16 months."},
    {"id":"precision-eng-senior-16","level":"senior","profession":"engineer","title":"Data to decision in one line","scenario":"You have three charts showing incident trends. In the board meeting you have time for one sentence, not three charts. The board pays you to compress the data into a decision-relevant insight.","task":"Write the single sentence that turns the three charts into one insight and its implication.","tips":["Boards don't want your analysis process — they want your conclusion.","Combine the trends into one claim, then say what it means for a decision.","If the three charts don't converge on one point, you have three messages, not one."],"focus":["precision","structure"]},
    {"id":"precision-eng-senior-17","level":"senior","profession":"engineer","title":"The security claim under scrutiny","scenario":"The audit committee asks how confident you are in your access controls. Your draft says 'very confident.' That answer invites the follow-up 'based on what?' — and you need to answer it before they ask.","task":"Replace 'very confident' with a claim grounded in specific evidence.","tips":["Confidence without evidence is an opinion; ground it in a control that fired.","Cite the test, the audit result, or the coverage figure.","Name the one gap you know about — it makes the rest credible."],"focus":["precision","impact"]},
    {"id":"precision-eng-senior-18","level":"senior","profession":"engineer","title":"The estimate with a range","scenario":"The CEO asks how long the platform consolidation will take. Your honest answer is a range, not a point, and pretending otherwise sets up a broken promise. But 'it depends' is unhelpful.","task":"Give a ranged estimate with the driver that determines where in the range you land.","tips":["A false-precise single date is worse than an honest range.","Give low and high, then the one variable that moves you between them.","Commit to when you'll be able to narrow the range."],"focus":["precision","clarity"],"placeholder":"Two to three quarters — closer to two if we freeze new features on the legacy system, three if we don't."},
    {"id":"precision-eng-senior-19","level":"senior","profession":"engineer","title":"The 'industry-leading' that says nothing","scenario":"Your investor-call brief describes your infrastructure as 'best-in-class' and 'industry-leading.' Analysts discount those phrases entirely. You need the specific number that earns the claim.","task":"Replace the superlatives with one benchmarked figure.","tips":["Analysts have heard 'best-in-class' from everyone — it's noise.","One number against a known benchmark carries more than any adjective.","If you can't benchmark it, don't claim leadership on it."],"focus":["precision","audience"],"placeholder":"Our p99 latency is 90ms — roughly half the median for platforms at our scale."},
    {"id":"precision-eng-senior-20","level":"senior","profession":"engineer","title":"Attribute the number to its source","scenario":"Your board slide shows a productivity gain of 30%. A director asks where it came from. If you can't name the source and method, the number becomes a liability instead of an asset.","task":"Restate the claim with its measurement source and method in one clause.","tips":["An unsourced number is a hostage to the first skeptic.","Name what you measured and how — cycle time, from ticketing data, quarter over quarter.","Sourcing a number is what separates evidence from assertion."],"focus":["precision","clarity"]},
    {"id":"precision-eng-senior-21","level":"senior","profession":"engineer","title":"The customer-impact number for the letter","scenario":"Your outage apology letter to a customer says the issue 'may have affected your operations.' Their CTO wants to know exactly what happened to their data and their users, in numbers.","task":"Rewrite the impact statement with specific figures for that customer.","tips":["'May have affected' reads as evasive to a technical customer — be exact.","Give them their numbers: their failed requests, their affected users, their duration.","If no data was lost, say so precisely; that's the fact they most want."],"focus":["precision","audience"],"placeholder":"For 47 minutes, roughly 340 of your API calls failed and retried; no data was lost or corrupted."},
    {"id":"precision-eng-senior-22","level":"senior","profession":"engineer","title":"From 'a bit behind' to the real gap","scenario":"You tell the CEO hiring is 'a bit behind.' The truth is you're 8 hires short of a 20-hire plan at the half-year mark — meaningfully behind. Softening the number now creates a bigger surprise later.","task":"State the hiring status with the exact numbers and what they imply for the plan.","tips":["'A bit behind' on a number you know is a small lie that compounds.","Give the plan, the actual, and the gap as figures.","Precision on the miss earns trust for your recovery plan."],"focus":["precision","impact"],"placeholder":"We're 8 of 20 hires in at the half-year mark — 4 behind pace, which puts the payments team's timeline at risk."},
    {"id":"precision-eng-senior-23","level":"senior","profession":"engineer","title":"The benchmark the board will want","scenario":"You tell the board engineering is 140 people. The board's real question is whether that's efficient — is 140 a lot or a little for your revenue and stage? A raw headcount without a benchmark can't be judged.","task":"Restate the headcount with the benchmark that makes it meaningful.","tips":["A number is only judgeable against a reference — supply the reference.","Revenue per engineer, or headcount versus comparable-stage peers, gives it meaning.","Preempt the 'is that a lot?' question by answering it."],"focus":["precision","audience"],"placeholder":"We're 140 engineers on $85M revenue — about $600K per engineer, in line with SaaS peers at our stage."},
    {"id":"precision-eng-senior-24","level":"senior","profession":"engineer","title":"The forecast that hedges too hard","scenario":"The CFO wants next year's infrastructure budget. Your draft says spend 'will likely be somewhere in the general vicinity of last year, give or take.' She needs a number to plan against, with the assumptions stated.","task":"Give a specific budget figure with the two assumptions it rests on.","tips":["A budget forecast has to be a number, not a mood — commit.","State the figure, then the two drivers that would move it.","Own the estimate and the assumptions; that's how she can hold you to it fairly."],"focus":["precision","clarity"],"placeholder":"I'm forecasting $4.8M, up 6% — assuming usage grows 25% and our consolidation lands by Q2."},
    {"id":"precision-eng-senior-25","level":"senior","profession":"engineer","title":"One number, made to matter","scenario":"You want the board to feel the weight of the reliability work. You have the figure — 14 hours of customer-facing downtime last year, down to a projected 2 this year. Stated flatly it slides past; made concrete it lands.","task":"State the before/after downtime numbers and translate them into a stake the board feels.","tips":["A precise number lands harder when tied to a consequence the reader values.","Convert hours of downtime into the thing it costs: revenue, churn, trust.","Pair the figure with the human or business meaning, in one breath."],"focus":["precision","impact"],"placeholder":"We're cutting customer-facing downtime from 14 hours to a projected 2 — roughly $1.5M of at-risk revenue protected."}
  ],
  "executive-presence": [
    {"id":"presence-eng-senior-01","level":"senior","profession":"engineer","title":"Own the recommendation, don't present the menu","scenario":"You bring the exec committee three architecture options with pros and cons for each and no recommendation. The CEO's response: 'You're the expert — what should we do?' A neutral menu abdicates the job they hired you for.","task":"Rewrite the close as a clear recommendation with the one reason, keeping the options as backup.","tips":["Presenting options without a pick reads as fear of being wrong, not fairness.","Say which one and why in one sentence; keep the others as the analysis behind it.","Executives can overrule a recommendation; they can't act on a menu."],"focus":["impact","structure"],"placeholder":"I recommend option B — it's the only one that ships before Black Friday. Here's how it compares."},
    {"id":"presence-eng-senior-02","level":"senior","profession":"engineer","title":"Separate fact from judgment","scenario":"In your incident brief you write 'the deploy was reckless.' That blends a fact (the deploy skipped review) with your judgment (it was reckless). Executives need to see which is which to trust your read.","task":"Rewrite the line separating the observed fact from your explicit judgment.","tips":["Blur fact and judgment and the reader can't tell what happened from what you think.","State the fact plainly, then label your assessment as yours.","'I consider that a serious lapse' is judgment owned; 'reckless' smuggled into a fact is not."],"focus":["precision","clarity"],"placeholder":"The deploy skipped the mandatory review step. In my judgment that's a serious process failure, not a one-off."},
    {"id":"presence-eng-senior-03","level":"senior","profession":"engineer","title":"Signpost the structure aloud","scenario":"You have three minutes in exec staff to cover the platform decision. Without signposting, the CEO can't tell where you are or when you'll land. You need to frame the shape before the content.","task":"Write the one-sentence signpost that opens your three minutes.","tips":["Telling the room the shape ('one recommendation, two risks, one ask') lets them follow.","Signposting reads as command of the material, not scriptedness.","End the signpost with the ask, so they listen for the decision."],"focus":["structure","impact"],"placeholder":"I'll give you my recommendation, the two risks it carries, and the one decision I need from you today."},
    {"id":"presence-eng-senior-04","level":"senior","profession":"engineer","title":"Drop the qualifiers that shrink you","scenario":"You open your board recommendation with 'This might just be my opinion, but I could be wrong, and I'm not the expert on the business side.' Every qualifier hands away the authority the board needs you to hold.","task":"Rewrite the opening with earned confidence and no self-diminishing qualifiers.","tips":["Pre-emptive self-doubt invites the room to doubt you too.","State your view as a view held firmly, not as a confession.","Confidence isn't arrogance — it's not making them carry your insecurity."],"focus":["impact","clarity"],"placeholder":"My recommendation is clear: we consolidate onto one platform this year."},
    {"id":"presence-eng-senior-05","level":"senior","profession":"engineer","title":"The stand behind an unpopular call","scenario":"You're recommending against a feature the CEO personally championed, because it would compromise reliability. The room can feel your reluctance. Presence here means stating the call cleanly, not hedging to soften the disagreement.","task":"Write the 2-3 sentence recommendation that respectfully holds the unpopular position.","tips":["Disagreeing up requires more clarity, not less — mush reads as cowardice.","Acknowledge the goal, then state why your call serves it better.","Give your reason once, firmly; don't over-justify a sound position."],"focus":["impact","clarity"]},
    {"id":"presence-eng-senior-06","level":"senior","profession":"engineer","title":"The confident 'here's what we'll do'","scenario":"Mid-outage, the exec team looks to you. Your draft update is full of 'we're trying to,' 'we hope to,' 'we might be able to.' In a crisis, tentative language spreads panic; the room needs to hear command.","task":"Rewrite the update in the voice of someone in control: what you are doing, in definite terms.","tips":["Crisis is when presence matters most — say 'we are,' not 'we hope to.'","State the plan as a plan, with a next checkpoint time.","Calm certainty about the process reassures even when the outcome is unknown."],"focus":["impact","clarity"],"placeholder":"Here's what we're doing: we've isolated the failing service and are rerouting traffic now. Next update in 20 minutes."},
    {"id":"presence-eng-senior-07","level":"senior","profession":"engineer","title":"Take the position the data supports","scenario":"Your analysis clearly favors buying over building, but your memo hedges to 'both options have merit' to avoid ruffling the build-it faction on your team. The CFO needs your actual position, not diplomatic neutrality.","task":"Rewrite the thesis to take the position your analysis supports.","tips":["'Both have merit' when the data doesn't is false balance, and executives see through it.","Take the position; handle the internal faction separately, not by watering down the memo.","Your job is the right answer, not the comfortable one."],"focus":["impact","precision"]},
    {"id":"presence-eng-senior-08","level":"senior","profession":"engineer","title":"The pause instead of the filler","scenario":"When the board asks a hard question, you fill the thinking time with 'um, so, yeah, I mean, that's a great question.' The filler undercuts the authority of whatever you say next. Presence is being comfortable with a beat of silence.","task":"Write the composed opening you'd use after a hard board question — no filler, buying yourself a beat.","tips":["'That's a great question' is filler that flatters instead of answering.","A short, honest framing beats verbal padding: 'The short answer is yes; here's the nuance.'","A two-second pause reads as thoughtfulness, not uncertainty."],"focus":["impact","clarity"],"placeholder":"The honest answer is that it's a risk, and here's how I'm managing it."},
    {"id":"presence-eng-senior-09","level":"senior","profession":"engineer","title":"Recommend, then invite challenge","scenario":"You want to project confidence without shutting down debate. Weak leaders either present no view or defend theirs to the death. Presence is stating your recommendation firmly and then genuinely opening it to challenge.","task":"Write the two sentences: your firm recommendation, then a real invitation to pressure-test it.","tips":["Confidence and openness coexist — a strong view, loosely held.","State the recommendation without hedging, then name where you're least sure.","Inviting challenge on a firm position reads as strength, not doubt."],"focus":["impact","clarity"],"placeholder":"I recommend we sunset the legacy product this quarter. The part I'd most want you to push on is the customer-migration timeline."},
    {"id":"presence-eng-senior-10","level":"senior","profession":"engineer","title":"Own the miss without collapsing","scenario":"You missed the hiring target and you're presenting to the CEO. There's a failure mode of grovelling and one of deflecting. Presence is owning the miss plainly and pivoting to the plan, from a position of composure.","task":"Write the 2-3 sentence statement: own the miss, no excuses, then the recovery.","tips":["Own it in one clean sentence — over-apologizing is as weak as deflecting.","No 'but' that shifts blame; the miss is yours, the plan is your credibility.","Composure while owning a miss is what senior looks like."],"focus":["impact","clarity"],"placeholder":"We missed hiring by four, and that's on me. Here's what I've changed so next quarter lands."},
    {"id":"presence-eng-senior-11","level":"senior","profession":"engineer","title":"The judgment call the board wants named","scenario":"The board wants your judgment on whether to accept the acquisition target's technology as-is or require a rebuild clause. You keep reciting facts. They have the facts; they want you to say what you'd do.","task":"State your judgment call in one sentence, clearly flagged as your recommendation.","tips":["Facts inform; judgment decides — the board is paying for the second.","Say 'my recommendation is' and then commit to it.","Naming it as judgment (not fact) is honest and still authoritative."],"focus":["impact","clarity"],"placeholder":"My judgment: require a rebuild clause — the platform won't survive our scale without one."},
    {"id":"presence-eng-senior-12","level":"senior","profession":"engineer","title":"The vendor negotiation stance","scenario":"You're in the room negotiating the cloud renewal. Your team's draft talking points are apologetic — 'we understand you have costs too, we don't want to be difficult.' Presence at the table means holding your position without hostility.","task":"Rewrite the opening stance: firm on your number, professional, unapologetic.","tips":["Apologizing for your ask hands the counterparty leverage for free.","Firm and cordial coexist — state the number as reasonable and expected.","Presence in negotiation is comfort with the other side's discomfort."],"focus":["impact","clarity"],"placeholder":"For a three-year commit at this volume, 28% is the market rate — that's where we need to land."},
    {"id":"presence-eng-senior-13","level":"senior","profession":"engineer","title":"The clear 'I've decided'","scenario":"Your directors are split on the database migration approach and looking to you to break the tie. Your draft says 'maybe we could consider possibly going with the phased approach?' They need a decision, said as a decision.","task":"State the decision as a decision, with the one reason, in two sentences.","tips":["Tie-breaking is your job — 'maybe we could' isn't breaking anything.","'We're going with X because Y' ends the debate and lets people execute.","Decisiveness respects your team's time more than endless optionality."],"focus":["impact","clarity"],"placeholder":"We're going with the phased migration — it protects revenue during the cutover. Let's build the plan around that."},
    {"id":"presence-eng-senior-14","level":"senior","profession":"engineer","title":"Present the trade-off, then choose","scenario":"Every real decision is a trade-off, and juniors hide the trade-off while seniors name it and still choose. You're recommending speed over completeness for the launch. Name the cost of your choice, then own it.","task":"Write the recommendation that names the trade-off and still commits to a side.","tips":["Naming the downside of your own recommendation builds trust, not doubt.","'We're choosing speed, which means we ship without X — and that's the right call because Z.'","Owning the trade-off is more authoritative than pretending there isn't one."],"focus":["impact","structure"],"placeholder":"We should ship in March without the analytics dashboard. We lose a nice-to-have; we gain the whole holiday quarter."},
    {"id":"presence-eng-senior-15","level":"senior","profession":"engineer","title":"The steady voice in the all-hands Q&A","scenario":"At the all-hands, an engineer challenges your reorg decision publicly and sharply. The room watches how you handle it. Presence is receiving the challenge without defensiveness and answering with composure.","task":"Write your composed 2-3 sentence response to the public challenge.","tips":["A public challenge is a presence test — react, and you lose the room.","Acknowledge the concern as legitimate, then answer it directly.","Steady tone matters as much as the words; don't match their heat."],"focus":["impact","audience"]},
    {"id":"presence-eng-senior-16","level":"senior","profession":"engineer","title":"State the recommendation before the analysis","scenario":"Your build-vs-buy deck saves the recommendation for slide 20, walking the CFO through every step first. Presence is leading with your conclusion and letting the analysis defend it, not building suspense.","task":"Write the opening line that states the recommendation up front, before any analysis.","tips":["Making the CFO wait 20 slides for your view reads as hedging.","Lead with the answer; the analysis becomes support, not suspense.","Confidence is showing your conclusion first and inviting scrutiny of the path to it."],"focus":["impact","structure"],"placeholder":"My recommendation is buy, and the next ten minutes are why — starting with the number that decides it."},
    {"id":"presence-eng-senior-17","level":"senior","profession":"engineer","title":"The honest confidence level","scenario":"The CEO asks how sure you are the launch holds. False bravado ('100%, no problem') destroys trust when it slips; false modesty ('who knows') is useless. Presence is a calibrated, owned confidence level.","task":"State your confidence as a calibrated level with the reason for it.","tips":["A real number ('I'm about 80% confident') reads as more credible than bravado.","Attach the confidence to the specific risk that would move it.","Owning a calibrated estimate is presence; hiding behind certainty or vagueness isn't."],"focus":["impact","precision"],"placeholder":"I'm about 80% confident — the one thing that would change that is the payment vendor's certification timing."},
    {"id":"presence-eng-senior-18","level":"senior","profession":"engineer","title":"Lead the room to the decision","scenario":"The exec committee is circling the platform decision without landing it. As the domain owner, presence means driving to a decision, not waiting to be asked. You need to name the decision and push for it.","task":"Write the sentence that names the decision on the table and asks for it now.","tips":["Presence is sometimes just naming that a decision is needed and calling for it.","Summarize the choice cleanly, then ask the room to make it today.","Driving to a decision is leadership; letting it drift is not."],"focus":["impact","structure"],"placeholder":"We have what we need to decide. The choice is consolidate now or wait a year — I recommend now, and I'd like us to settle it today."},
    {"id":"presence-eng-senior-19","level":"senior","profession":"engineer","title":"The judgment on ambiguous data","scenario":"The reliability data is genuinely ambiguous, and the CFO asks what it means. You could hide in the ambiguity. Presence is offering your interpretation clearly while being honest that it's a judgment on incomplete data.","task":"Give your interpretation of the ambiguous data in two sentences, owned as judgment.","tips":["Ambiguous data still needs someone to read it — that's your job.","Offer your read plainly, then flag the uncertainty honestly.","Hiding in 'the data is unclear' abdicates the interpretation they need."],"focus":["impact","precision"]},
    {"id":"presence-eng-senior-20","level":"senior","profession":"engineer","title":"The unhedged 'no' to the board","scenario":"A board member proposes accelerating the launch by cutting the security review. You need to say no, firmly, without the pile of qualifiers that would make it sound negotiable. Presence is a clean, respectful, unmovable no.","task":"Write the 2-sentence no: firm, reasoned, respectful.","tips":["A hedged no on a safety matter invites renegotiation — be clear it isn't one.","State the no, then the one reason it's non-negotiable.","Respectful and firm: you're protecting them from a decision they'd regret."],"focus":["impact","clarity"],"placeholder":"I can't recommend cutting the security review, and I'd advise against it. Shipping unreviewed payment code is the one risk we shouldn't take."},
    {"id":"presence-eng-senior-21","level":"senior","profession":"engineer","title":"The recommendation for the QBR close","scenario":"Your QBR has walked through the quarter well, but it ends by trailing off into 'so, that's where we are.' Presence is closing with a forward recommendation, not a summary — telling the room what you're asking for next.","task":"Write the QBR's closing 2 sentences: the forward ask, stated with conviction.","tips":["A QBR that ends in summary wastes the momentum you built — end with an ask.","State clearly what you want for next quarter and why it follows from the results.","The close is what the room remembers; make it a recommendation, not a recap."],"focus":["impact","structure"]},
    {"id":"presence-eng-senior-22","level":"senior","profession":"engineer","title":"Distinguish 'I know' from 'I believe'","scenario":"Briefing the CEO on the acquisition target, you present everything with equal certainty. Some of it you've verified; some is your informed belief. Presence is signaling which is which so she can weight your words.","task":"Rewrite a two-claim statement flagging one as verified fact and one as your belief.","tips":["Equal certainty on unequal evidence erodes trust when the softer claim slips.","'I've confirmed X; I believe Y but haven't verified it' is more authoritative, not less.","Calibrated language is a presence marker — it shows you know what you know."],"focus":["impact","precision"],"placeholder":"I've confirmed their uptime numbers directly. I believe their team will stay through the transition, but I haven't been able to verify that."},
    {"id":"presence-eng-senior-23","level":"senior","profession":"engineer","title":"The composed correction of the CEO","scenario":"In the board meeting the CEO states an engineering fact that's wrong in a way that matters. Presence is correcting it cleanly and without drama, in front of the board, without undermining her.","task":"Write the 1-2 sentence correction: accurate, composed, face-saving.","tips":["Correcting up in public is a presence high-wire — be brief and unflustered.","Frame it as adding precision, not catching an error.","'Let me sharpen that slightly' lands better than 'that's not right.'"],"focus":["impact","audience"],"placeholder":"Let me sharpen one number there — it's a six-week slip, not two, which actually strengthens the case for the extra hire."},
    {"id":"presence-eng-senior-24","level":"senior","profession":"engineer","title":"The 'this is my call' moment","scenario":"A decision falls squarely in your domain, and the exec team is deferring in a way that will diffuse accountability. Presence is claiming the decision explicitly — 'this one's mine, and here's what I'm deciding.'","task":"Write the two sentences that claim the decision as yours and state it.","tips":["Diffuse ownership kills decisions — claim the ones that are rightly yours.","'This is my call to make, and I'm making it' is presence in one line.","Claiming accountability up front is more reassuring than committee ownership."],"focus":["impact","clarity"],"placeholder":"This is an engineering call, so I'll make it: we hold the launch two weeks to finish the security review. I own that decision and its consequences."},
    {"id":"presence-eng-senior-25","level":"senior","profession":"engineer","title":"The full-presence board narrative","scenario":"You have five minutes to give the board your technology narrative for the year. It needs a clear thesis, an owned recommendation, honest acknowledgment of risk, and calm confidence — everything this module has practiced, in one delivery.","task":"Write the opening 3-4 sentences that set thesis, recommendation, and named risk with presence.","tips":["Open with the thesis, not a warm-up — the board is calibrating you in the first ten seconds.","State one clear recommendation and name the biggest risk to it in the same breath.","Confidence plus honesty about risk is the full presence signature — neither alone suffices."],"focus":["impact","structure"],"placeholder":"My thesis for the year is simple: we make the platform boring, and that's a competitive advantage. I'm recommending we invest $3M to consolidate — the biggest risk is execution during the payments launch, and here's how I'm managing it."}
  ],
  "answering-under-pressure": [
    {"id":"pressure-eng-senior-01","level":"senior","profession":"engineer","title":"Answer the question actually asked","scenario":"In the board meeting a director asks: 'Are we going to hit the launch date?' You start explaining the sprint methodology and dependency chains. The director interrupts: 'Yes or no?' You buried the answer in process.","task":"Answer the yes/no question first, then add the one qualifier that matters.","tips":["A yes/no question gets a yes or no in the first word — then the nuance.","Explaining process before answering reads as dodging.","One qualifier is honest; a paragraph of them is evasion."],"focus":["clarity","impact"],"placeholder":"Yes — assuming the payment vendor certifies us by the 20th, which I expect."},
    {"id":"pressure-eng-senior-02","level":"senior","profession":"engineer","title":"The honest 'I don't know' with a path","scenario":"The CFO asks the exact dollar impact of yesterday's outage. You don't have it yet — the reconciliation runs tomorrow. Bluffing a number would be worse than admitting you don't have it. But 'I don't know' alone is unsatisfying.","task":"Say you don't know yet, then give the path and the time you'll have it.","tips":["'I don't know' plus a path is strength; a guessed number is a future liability.","Name when and how you'll have the answer.","Under pressure, the credible move is the honest one with a commitment attached."],"focus":["clarity","precision"],"placeholder":"I don't have the exact figure yet — reconciliation finishes tomorrow, and I'll have a firm number by noon."},
    {"id":"pressure-eng-senior-03","level":"senior","profession":"engineer","title":"Pushback with specifics, not defensiveness","scenario":"A board member says 'Engineering always overspends on infrastructure.' Your instinct is to get defensive. The stronger move is to meet the challenge with a specific fact that reframes it, without heat.","task":"Write the 2-3 sentence response: acknowledge, then counter with a specific.","tips":["Defensiveness confirms the accusation; a specific fact dissolves it.","Acknowledge the concern's legitimacy before countering — it lowers the temperature.","One number ('unit cost is down 13%') beats any amount of protest."],"focus":["clarity","precision"],"placeholder":"It's a fair thing to watch. Actually, total spend is up 22% but usage is up 40% — our cost per transaction fell 13% this year."},
    {"id":"pressure-eng-senior-04","level":"senior","profession":"engineer","title":"The hostile 'why should we trust you' question","scenario":"After the second outage this quarter, an executive asks pointedly: 'Why should we believe the next fix will work when the last one didn't?' The question is loaded. Composure and specifics beat indignation.","task":"Write the 2-3 sentence answer that earns trust through specifics, not reassurance.","tips":["Meet a trust challenge with evidence, not with 'trust me.'","Acknowledge the prior failure honestly — denial destroys the trust you're rebuilding.","Point to the concrete difference between then and now."],"focus":["clarity","impact"]},
    {"id":"pressure-eng-senior-05","level":"senior","profession":"engineer","title":"The interruption mid-answer","scenario":"You're two sentences into answering the CEO when the CFO cuts in with a different question entirely. You need to acknowledge the new question, decide the order, and not lose the thread — without looking rattled.","task":"Write the composed 1-2 sentence bridge that handles both questions and their order.","tips":["Acknowledge the interruption, then take control of the sequencing.","'Let me finish this point in ten seconds, then take yours' is composed, not evasive.","Losing the thread under interruption is the failure — hold both questions."],"focus":["clarity","structure"],"placeholder":"Let me land this point, then I'll take your cost question directly — they're actually connected."},
    {"id":"pressure-eng-senior-06","level":"senior","profession":"engineer","title":"The question you can't fully answer publicly","scenario":"In the all-hands Q&A, someone asks whether the reorg means layoffs are coming. You know some detail you can't share yet. You must be honest without disclosing what you can't, and without a non-answer that reads as a cover-up.","task":"Write the 2-3 sentence answer: honest about what you can and can't say, no evasion.","tips":["Say what you can commit to now and be explicit about what you can't yet say and why.","A transparent 'I can't answer that yet, here's when I can' beats a slippery dodge.","Never say something you'll have to walk back — that's worse than the hard question."],"focus":["clarity","audience"]},
    {"id":"pressure-eng-senior-07","level":"senior","profession":"engineer","title":"The 'that's not what I asked' recovery","scenario":"The CEO asked why costs rose, and you answered why usage grew — related but not the question. She says 'that's not what I asked.' You need to recover cleanly, answer the real question, and not compound it with flailing.","task":"Write the recovery: acknowledge the miss and answer the actual question in two sentences.","tips":["Don't defend the wrong answer — pivot cleanly to the right one.","'You're right, let me answer directly' costs nothing and buys goodwill.","Then actually answer the question asked, precisely."],"focus":["clarity","impact"],"placeholder":"You're right — the direct answer is that costs rose 22% specifically because of the one-time data migration, which ends this week."},
    {"id":"pressure-eng-senior-08","level":"senior","profession":"engineer","title":"The loaded premise in the question","scenario":"A director asks: 'Given that our tech is falling behind, what's your plan to catch up?' The premise — that you're falling behind — is wrong and you can't just answer within it. You must correct the premise without seeming defensive.","task":"Write the 2-3 sentence response that respectfully corrects the premise, then answers.","tips":["Answering a false premise validates it — address the premise first.","Correct it with a fact, not a protest, then answer the real underlying concern.","Keep the tone collaborative; you're informing, not arguing."],"focus":["clarity","precision"]},
    {"id":"pressure-eng-senior-09","level":"senior","profession":"engineer","title":"Under fire in the customer escalation call","scenario":"On a call with your biggest customer's angry CTO after the outage, he demands: 'How do I know this won't happen again next week?' You can't promise perfection. You must be honest about that and still give him real confidence.","task":"Write the 2-3 sentence answer: honest about certainty, concrete about the specific safeguard.","tips":["Promising it'll never happen again is a lie he'll remember — don't.","Give the specific control you've added, tied to this specific failure.","Honesty about residual risk, paired with concrete action, is what rebuilds trust."],"focus":["clarity","audience"]},
    {"id":"pressure-eng-senior-10","level":"senior","profession":"engineer","title":"The rapid-fire board Q&A","scenario":"The board is firing quick questions and you feel the urge to over-explain each one, which eats time and invites more questions. Under this pressure, the discipline is short, direct answers with an offer to go deeper.","task":"Write a tight answer to 'Is the security finding closed?' — direct, with a door open for more.","tips":["In rapid-fire, brevity is control — long answers invite pile-on.","Answer, then offer detail rather than forcing it: 'Happy to go deeper if useful.'","Over-explaining under pressure signals nervousness."],"focus":["clarity","concision"],"placeholder":"Closed — remediation completed and re-audited last week. Happy to walk through the details if the committee wants them."},
    {"id":"pressure-eng-senior-11","level":"senior","profession":"engineer","title":"The gotcha about a past commitment","scenario":"A director says: 'Last quarter you said reliability would be fixed. Here we are with another outage.' It's a fair hit. You need to own the gap between the commitment and reality without excuses, and reset credibly.","task":"Write the 2-3 sentence response: own the gap, no excuse, credible reset.","tips":["Don't relitigate what you meant — own the gap as they experienced it.","One honest sentence of accountability, then what's genuinely different now.","A credible reset requires acknowledging the last one didn't fully work."],"focus":["clarity","impact"]},
    {"id":"pressure-eng-senior-12","level":"senior","profession":"engineer","title":"The CFO's 'prove it' challenge","scenario":"You claim the platform investment will pay back in 16 months. The CFO says: 'Prove it — walk me through the math right now.' You need to defend the number live, without notes, without getting flustered by the demand.","task":"Write the 3-sentence walkthrough of the payback math, delivered under pressure.","tips":["Know your own headline math well enough to recite it cold — that's the preparation.","Walk the three numbers: cost, annual saving, payback period.","If one input is an assumption, name it as such rather than pretending it's a fact."],"focus":["clarity","precision"],"placeholder":"$400K upfront; it cuts release-incident costs by about $300K a year; that's a 16-month payback, assuming our current release cadence holds."},
    {"id":"pressure-eng-senior-13","level":"senior","profession":"engineer","title":"The question outside your expertise","scenario":"In exec staff, someone asks you a legal question about data-residency obligations. It's adjacent to your work but genuinely legal. You shouldn't guess, but 'not my area' alone is unhelpful. Route it well.","task":"Write the 1-2 sentence response: honest boundary, useful redirect.","tips":["Guessing outside your lane is how you create problems for other functions.","Say what you do know, flag the boundary, and name who owns the rest.","Routing cleanly is more senior than pretending to have all answers."],"focus":["clarity","impact"],"placeholder":"Technically we can restrict data to a region; whether that satisfies the obligation is a legal call, and I'd want counsel to confirm before we commit."},
    {"id":"pressure-eng-senior-14","level":"senior","profession":"engineer","title":"The public disagreement from a peer","scenario":"In the exec meeting, the head of product publicly says your reliability focus is slowing the roadmap. You disagree, and the room is watching. You need to hold your position with specifics, not turn it into a visible fight.","task":"Write the 2-3 sentence response: hold your ground, with data, without escalating.","tips":["Meet a peer's challenge with a fact and a shared goal, not a counterattack.","Acknowledge the tension is real, then reframe it around the common objective.","Data cools a disagreement that emotion would inflame."],"focus":["clarity","precision"]},
    {"id":"pressure-eng-senior-15","level":"senior","profession":"engineer","title":"The 'just give me a date' demand","scenario":"The CEO is done with your ranges and says: 'I don't want a range, I want a date I can give the board.' You genuinely have uncertainty, but she needs commitment. You have to give a date and own the risk around it.","task":"Write the 2-sentence response: commit to a date, name the one risk to it.","tips":["When a range won't do, pick the date you'll defend and commit.","Attach the single biggest risk so the commitment is honest, not reckless.","Committing to a date under pressure — and owning it — is the senior move."],"focus":["clarity","impact"],"placeholder":"March 4 — you can give the board that. The one thing that could move it is the payment vendor's certification, and I'll flag it immediately if it slips."},
    {"id":"pressure-eng-senior-16","level":"senior","profession":"engineer","title":"The blame-seeking question after an incident","scenario":"In the incident review, an executive asks: 'Whose fault was this?' The honest, useful answer is about the process gap, not a person. Under pressure you must redirect from blame to system without seeming to protect anyone.","task":"Write the 2-3 sentence answer that redirects from person to process, honestly.","tips":["Naming a scapegoat feels satisfying and fixes nothing — redirect to the system.","Be specific about the process gap so it doesn't read as protecting someone.","'The failure was a missing control, not a person' is both true and forward-looking."],"focus":["clarity","structure"]},
    {"id":"pressure-eng-senior-17","level":"senior","profession":"engineer","title":"The skeptical 'is AI just hype for us' question","scenario":"A board member asks bluntly: 'Is all this AI spend just following the herd?' It's a fair skeptical challenge. You need to answer with your actual reasoning, conceding what's uncertain, not with defensive enthusiasm.","task":"Write the 2-3 sentence answer that engages the skepticism honestly.","tips":["Matching skepticism with hype confirms the board member's fear.","Concede the parts that are genuinely a bet — that earns trust for the parts that aren't.","Ground it in one specific, shipped or measurable application."],"focus":["clarity","impact"]},
    {"id":"pressure-eng-senior-18","level":"senior","profession":"engineer","title":"The follow-up that keeps digging","scenario":"You answered the outage question, but the director keeps pressing: 'But why did the review get skipped in the first place?' Each follow-up goes a level deeper. You must stay composed and keep answering honestly rather than deflecting the deeper cause.","task":"Write the honest 2-sentence answer to the deeper 'why,' without deflecting.","tips":["Persistent follow-ups test whether you understand your own failure — meet them.","Go the level deeper honestly, even when it's less flattering.","Deflecting a legitimate 'why' reads worse than the underlying cause."],"focus":["clarity","impact"]},
    {"id":"pressure-eng-senior-19","level":"senior","profession":"engineer","title":"The 'what would you cut' pressure","scenario":"The CFO says the budget is being cut 15% and asks, live, what you'd cut. You haven't finalized it, but 'I need time' won't satisfy her. You must give a real directional answer while flagging it's preliminary.","task":"Write the 2-3 sentence answer: a real directional cut, honestly flagged as preliminary.","tips":["A preliminary but real answer beats stalling under budget pressure.","Name the category you'd cut first and the one you'd protect, with reasons.","Flag it as directional, then commit to the detailed plan by a date."],"focus":["clarity","structure"]},
    {"id":"pressure-eng-senior-20","level":"senior","profession":"engineer","title":"The question designed to make you overpromise","scenario":"An enterprise customer's CTO on a call asks: 'Can you guarantee 100% uptime if we sign?' Saying yes wins the moment and loses the relationship at the first outage. You must decline the false promise while keeping him confident.","task":"Write the 2-3 sentence answer that declines the overpromise and offers the real commitment.","tips":["The pressure is to say yes; the discipline is to promise what's true.","Replace '100%' with the real number and the real recovery commitment.","An honest SLA you'll hit beats a perfect one you'll break."],"focus":["clarity","precision"],"placeholder":"I won't promise 100% — nobody honest can. What I'll commit to in writing is 99.95% and sub-15-minute recovery, and we've hit both for six quarters."},
    {"id":"pressure-eng-senior-21","level":"senior","profession":"engineer","title":"The rapid reversal question","scenario":"You recommended building; new data mid-meeting shifts it toward buying, and a director notices you hesitate and asks 'so which is it?' Under pressure you must integrate the new information and give a clear answer, not freeze.","task":"Write the 2-sentence answer that updates cleanly on the new information.","tips":["Updating on new data is strength, not flip-flopping — say so plainly.","Name what changed and where it leaves you now.","Freezing reads worse than a clean, reasoned update."],"focus":["clarity","impact"],"placeholder":"With that cost figure, I'm updating my view — buy is now the right call, and here's the number that moved me."},
    {"id":"pressure-eng-senior-22","level":"senior","profession":"engineer","title":"The 'give me a straight answer' frustration","scenario":"You've been hedging and the CEO snaps: 'Stop hedging and give me a straight answer.' You realize your caution has read as evasion. You need to reset to directness immediately, even on genuinely uncertain matters.","task":"Rewrite a hedged answer as the straight version the CEO is demanding, keeping only essential uncertainty.","tips":["When called out for hedging, over-correct toward directness.","Give the single most likely answer plainly, then at most one real caveat.","Distinguish essential uncertainty from defensive hedging and cut the latter."],"focus":["clarity","impact"],"placeholder":"Straight answer: we make the date. The only thing that breaks it is the vendor, and I rate that low."},
    {"id":"pressure-eng-senior-23","level":"senior","profession":"engineer","title":"The board member who won't let go","scenario":"One board member returns to the same concern about vendor lock-in three times across the meeting. You've answered it, but the repetition signals they aren't satisfied. Under pressure you must address what's really unsatisfied, not just repeat.","task":"Write the 2-3 sentence response that addresses the underlying concern, not the surface question.","tips":["Repeated questions mean your answer missed the real worry — find it.","Name what you think the underlying concern is and speak to that.","Repeating your prior answer louder never works — go underneath it."],"focus":["clarity","audience"]},
    {"id":"pressure-eng-senior-24","level":"senior","profession":"engineer","title":"The ambush stat you can't verify live","scenario":"A director cites a statistic — 'competitors ship twice as fast as us' — that you suspect is wrong but can't verify in the room. You must neither accept a bad premise nor call them a liar. Handle the unverifiable claim with poise.","task":"Write the 2-sentence response that neither concedes nor confronts, and commits to verify.","tips":["Don't accept an unverified stat that reframes the discussion against you.","Don't attack the source either — question the number, not the person.","Commit to bringing verified data, and note your own contrary read if you have one."],"focus":["clarity","precision"],"placeholder":"That doesn't match what I've seen, but I don't want to argue numbers I can't verify here — let me bring you a benchmarked comparison this week."},
    {"id":"pressure-eng-senior-25","level":"senior","profession":"engineer","title":"The full pressure gauntlet","scenario":"You're presenting the platform investment case and the board hits you with three challenges in a row: the number's too big, the timing's wrong, and how do you know it'll work. You must field all three with composure, specifics, and without losing the thread of your ask.","task":"Write your composed response to the toughest of the three — 'how do you know it'll work' — in 2-3 sentences, then note how you'd keep the ask alive.","tips":["Under a barrage, address the toughest challenge with your best evidence first.","Concede what's genuinely uncertain, defend firmly what isn't.","After fielding challenges, always return to the ask — don't let it get buried."],"focus":["clarity","impact"]}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-eng-senior-01","level":"senior","profession":"engineer","title":"The before/after for the platform bet","scenario":"You're pitching the exec committee on consolidating three platforms into one. A list of technical benefits won't move them. A clear before-and-after — where you are now versus where this bet lands you — will.","task":"Write the 2-3 sentence before/after frame: today's painful state, the state after the investment.","tips":["Persuasion lives in the contrast between a painful now and a better then.","Make 'today' vivid and costly so the 'after' has something to relieve.","Keep both states concrete — a real number in each."],"focus":["impact","structure"],"placeholder":"Today, every feature crosses three platforms and takes six weeks. After this, it's one platform and two weeks — and we retire a whole vendor bill."},
    {"id":"narrative-eng-senior-02","level":"senior","profession":"engineer","title":"Make the tech-debt stakes concrete","scenario":"Your tech-debt investment case says the legacy system is 'risky' and 'hard to maintain.' Abstract risk doesn't move a CFO. You need the stakes as a concrete, felt scenario she can picture.","task":"Rewrite the stakes as a concrete scenario: what specifically breaks, and what it costs when it does.","tips":["Abstract risk persuades no one — turn it into a scene with a price tag.","Use a real recent incident as the picture of what's coming, worse.","Concreteness is what makes a CFO feel the risk, not just note it."],"focus":["impact","precision"],"placeholder":"Last quarter this system took checkout down for four hours on a Tuesday. On Black Friday, the same failure costs us roughly $2M an hour."},
    {"id":"narrative-eng-senior-03","level":"senior","profession":"engineer","title":"Pre-empt the strongest objection","scenario":"You're recommending building the feature-flag system in-house. The strongest objection is 'why not just buy one?' If you ignore it, the CFO raises it and you're on the back foot. Address it inside your case, on your terms.","task":"Write the 2-3 sentences that raise the buy objection yourself and answer it.","tips":["Raising the best counterargument yourself signals confidence and control.","Address it fairly — a strawman version fools no one and costs trust.","Answering it inside your narrative means it's settled before anyone else raises it."],"focus":["impact","precision"]},
    {"id":"narrative-eng-senior-04","level":"senior","profession":"engineer","title":"The reliability story for the board","scenario":"You want the board to fund reliability work, but 'we need to improve our SLOs' is not a story. Boards fund narratives with stakes: a threat, a turning point, a payoff. You have the raw material — rising incidents, a near-miss, a clear fix.","task":"Write the 3-sentence narrative arc: the rising threat, the turning point, the payoff of acting.","tips":["A funding case is a story: things are getting worse, here's the moment to act, here's the win.","The near-miss is your turning point — the moment that makes inaction a choice.","End on the payoff in the board's currency: protected revenue, protected trust."],"focus":["impact","clarity"]},
    {"id":"narrative-eng-senior-05","level":"senior","profession":"engineer","title":"Frame the AI investment as a choice","scenario":"You're pitching AI investment to the board. Framed as 'we should spend on AI,' it invites cost scrutiny. Framed as a choice between two futures — invest now or cede ground to competitors — it becomes about position, not spend.","task":"Write the 2-3 sentence framing that presents two futures and makes the choice clear.","tips":["Reframe a spend as a choice between two futures and the cost recedes.","Make the do-nothing future concrete and uncomfortable.","The choice frame puts the board in the decision, not just approving a budget."],"focus":["impact","clarity"]},
    {"id":"narrative-eng-senior-06","level":"senior","profession":"engineer","title":"The customer's story, not your architecture","scenario":"Pitching the platform rebuild to the exec team, you keep describing the architecture. What persuades is the customer's story: what a customer experiences today, and what they'll experience after. Center the human, not the system.","task":"Rewrite the pitch's core around a specific customer's before/after experience.","tips":["Executives are moved by customer experience, not architecture diagrams.","Pick one representative customer and tell their story concretely.","The architecture is how; the customer's better day is why."],"focus":["impact","audience"],"placeholder":"Today, an enterprise admin waits 30 seconds for a report and it sometimes times out. After the rebuild, it's instant — and that's the moment they stop evaluating competitors."},
    {"id":"narrative-eng-senior-07","level":"senior","profession":"engineer","title":"The stakes of the vendor lock-in","scenario":"You want to move off a vendor before renewal, and 'we're locked in' doesn't land. The stakes are concrete: the vendor knows you can't leave and is raising prices 40%, and next year it's worse. Make the trap vivid.","task":"Write the 2-3 sentences that make the lock-in stakes concrete and urgent.","tips":["A vivid picture of the trap tightening beats the abstract word 'lock-in.'","Show the trajectory — this year 40%, next year they own you.","Urgency comes from the closing window, so name when it closes."],"focus":["impact","clarity"]},
    {"id":"narrative-eng-senior-08","level":"senior","profession":"engineer","title":"Persuade the skeptical CFO on unit economics","scenario":"The CFO is skeptical the platform investment pays off. Numbers alone haven't moved her because she's seen optimistic engineering forecasts before. You need a narrative that acknowledges that history and earns trust for this forecast.","task":"Write the 2-3 sentence persuasion that acknowledges past optimism and differentiates this case.","tips":["When your credibility is discounted, address the discount directly.","Name the past over-promises before making a new promise — it disarms the skepticism.","Then show what's different: conservative assumptions, a tracked metric, a checkpoint."],"focus":["impact","precision"]},
    {"id":"narrative-eng-senior-09","level":"senior","profession":"engineer","title":"The org-change narrative that wins buy-in","scenario":"You're merging two teams and need the affected engineers to buy in, not just comply. A narrative that only serves the org ('efficiency') breeds cynicism. You need a story where the change is good for them, honestly told.","task":"Write the 2-3 sentence narrative that frames the merge as a genuine opportunity for the people in it.","tips":["People buy into change when they see themselves winning in it, honestly.","Find the real upside for engineers — bigger scope, less duplicated work, clearer path.","Don't oversell; a slightly-too-good story reads as spin and backfires."],"focus":["impact","audience"]},
    {"id":"narrative-eng-senior-10","level":"senior","profession":"engineer","title":"The turning-point moment in the postmortem","scenario":"You want the exec team to approve real prevention investment after the outage, not just note it. The persuasive frame casts this incident as a turning point: the moment you either invest or accept this as normal.","task":"Write the 2-3 sentences that frame the incident as a decision point, not just an event.","tips":["An incident is data; a turning point is a decision — frame it as the latter.","'This is the moment we decide whether four-hour outages are acceptable' forces a choice.","Tie the investment to preventing the specific recurrence, vividly."],"focus":["impact","clarity"]},
    {"id":"narrative-eng-senior-11","level":"senior","profession":"engineer","title":"Sell the boring platform investment","scenario":"Reliability and platform work is unglamorous, and the board is drawn to shiny product bets. You need a narrative that makes 'boring' compelling — reframing reliability as the foundation that makes every product bet possible.","task":"Write the 2-3 sentence narrative that makes reliability investment feel essential, not dull.","tips":["Reframe boring-but-critical work as the enabler of the exciting work.","Every product bet the board loves depends on the platform holding — say that.","Make the absence vivid: the shiny bet that fails because the foundation cracked."],"focus":["impact","clarity"],"placeholder":"Every product bet you're excited about rides on this platform. Boring is the point — boring is what lets us ship the exciting things without them breaking."},
    {"id":"narrative-eng-senior-12","level":"senior","profession":"engineer","title":"The negotiation narrative with the vendor","scenario":"You're negotiating the cloud renewal and want a big discount. Pure demand invites pushback. A narrative — you're a growing, reference-able customer whose expansion is worth more to them than the discount costs — reframes the ask as mutual.","task":"Write the 2-3 sentence framing that makes the discount serve the vendor's interest too.","tips":["The best negotiation narrative shows the counterparty why yes helps them.","Frame your discount as the price of a growing, quotable relationship.","Make the alternative — you shopping around — a loss for them, not a threat."],"focus":["impact","clarity"]},
    {"id":"narrative-eng-senior-13","level":"senior","profession":"engineer","title":"Pre-empt the 'we can't afford it' objection","scenario":"Your $3M tech-debt ask will hit an immediate 'we can't afford it right now.' Rather than wait for it, you fold the answer into the pitch: reframing the cost of not doing it as the larger, hidden number.","task":"Write the 2-3 sentences that pre-empt the affordability objection by pricing inaction.","tips":["The 'can't afford it' objection dies when inaction has a bigger price tag.","Price the status quo: incidents, lost velocity, the eventual forced rewrite.","Fold it in so the objection is answered before it's voiced."],"focus":["impact","precision"],"placeholder":"The real question isn't whether we can afford the $3M — it's whether we can afford the $5M in incidents and lost velocity this system costs us every year we wait."},
    {"id":"narrative-eng-senior-14","level":"senior","profession":"engineer","title":"The investor-call narrative on infrastructure","scenario":"On the investor call, you need the infrastructure story to sound like a moat, not a cost center. Analysts hear 'infrastructure' as expense unless you frame it as the thing that lets the business scale profitably.","task":"Write the 2-3 sentence narrative that frames infrastructure as competitive advantage.","tips":["Reframe a cost center as a moat: what does it let you do that rivals can't?","Tie it to a number analysts value: margin, scale without proportional cost.","The story is that your platform is why growth is profitable, not just possible."],"focus":["impact","audience"],"placeholder":"Our platform is why we can double customers while engineering grows 20% — it's not a cost, it's the reason our margins expand as we scale."},
    {"id":"narrative-eng-senior-15","level":"senior","profession":"engineer","title":"The change-story for adopting a new standard","scenario":"You're mandating a new deployment standard across all teams, and engineers resist mandates. A persuasive narrative shows the pain of the current inconsistency and the relief the standard brings — making adoption feel like liberation, not compliance.","task":"Write the 2-3 sentence narrative that sells the new standard as relief from a real pain.","tips":["Mandates persuade when they solve a pain the audience already feels.","Name the shared frustration the inconsistency causes today.","Frame the standard as the thing that ends that frustration, not new bureaucracy."],"focus":["impact","audience"]},
    {"id":"narrative-eng-senior-16","level":"senior","profession":"engineer","title":"The stakes for the security investment","scenario":"After the near-miss, you're asking for $1.2M in security work, and the room's mood is 'nothing actually happened.' Your narrative must make the averted disaster feel real — the crisis that almost was, and the next one that won't be a near-miss.","task":"Write the 2-3 sentence narrative that makes the near-miss feel like the warning it was.","tips":["A near-miss persuades only if you make people feel the disaster it nearly was.","Walk them through what would have happened if it hadn't been caught.","Then make clear the next one may not be caught — the window to prepare is now."],"focus":["impact","clarity"]},
    {"id":"narrative-eng-senior-17","level":"senior","profession":"engineer","title":"Persuade product to accept the reliability tax","scenario":"You need the product org to accept that 20% of engineering capacity goes to reliability, and they see it as tax on the roadmap. Your narrative must reframe it as insurance on the roadmap — the thing that keeps their launches from failing.","task":"Write the 2-3 sentence narrative that reframes the reliability allocation as protecting product's own goals.","tips":["Reframe a 'tax' as protection of the other side's most valued thing.","Show what happens to product's launches without the reliability investment.","Make it their win, not your cost — a launch that doesn't crash on day one."],"focus":["impact","audience"]},
    {"id":"narrative-eng-senior-18","level":"senior","profession":"engineer","title":"The acquisition-tech narrative for the board","scenario":"You assessed an acquisition target and support the deal despite a needed rebuild. The board will fixate on the $5M rebuild cost. Your narrative must frame the rebuild not as a hidden liability but as expected, priced, and worth it for what the deal delivers.","task":"Write the 2-3 sentence narrative that folds the rebuild cost into a still-positive deal story.","tips":["Don't let a real cost become a surprise — build it into the story up front.","Frame the rebuild as the known price of a valuable asset, already in your math.","End on what the deal delivers that's worth the total, rebuild included."],"focus":["impact","clarity"]},
    {"id":"narrative-eng-senior-19","level":"senior","profession":"engineer","title":"The 'why now' urgency","scenario":"Your platform consolidation is a good idea any year, which is exactly why it never gets funded — there's no urgency. This year there is: two of three platform leads leave, and the knowledge walks with them. Build the narrative around that closing window.","task":"Write the 2-3 sentences that establish 'why now' as a genuine, closing window.","tips":["A perennial good idea needs a 'why this year' to get funded.","The departures are your closing window — after them, the cost jumps.","Make inaction this year a concrete, dated loss."],"focus":["impact","clarity"],"placeholder":"We could consolidate any year — but two of our three platform leads leave by December, and after that we're rebuilding from documentation, not from people who know it."},
    {"id":"narrative-eng-senior-20","level":"senior","profession":"engineer","title":"Answer the 'what if it fails' objection","scenario":"Your big platform bet invites the objection: 'what if the migration fails and takes down production?' Ignoring it leaves the fear unaddressed. Pre-empt it by narrating how the plan makes failure survivable, not by pretending it can't happen.","task":"Write the 2-3 sentences that raise the failure fear and show how the plan contains it.","tips":["Address the fear directly — pretending failure is impossible increases the fear.","Show the containment: phased rollout, rollback, no big-bang cutover.","Confidence comes from a credible plan for when things go wrong, not from denial."],"focus":["impact","precision"]},
    {"id":"narrative-eng-senior-21","level":"senior","profession":"engineer","title":"The all-hands vision narrative","scenario":"At the engineering all-hands you want to rally the org around the year's direction. A list of priorities inspires no one. A narrative — where the org has been, the challenge ahead, and the future you're building toward — creates shared purpose.","task":"Write the 3-sentence narrative arc for the all-hands: past, challenge, future.","tips":["An org rallies around a story with a past, a present challenge, and a future.","Honor where the team has been before pointing where it's going.","Make the future concrete enough that people can see their part in it."],"focus":["impact","audience"]},
    {"id":"narrative-eng-senior-22","level":"senior","profession":"engineer","title":"Reframe the delay as the responsible choice","scenario":"You have to persuade the CEO that slipping the launch six weeks is the right call, not a failure. The narrative must reframe the delay from 'we couldn't deliver' to 'we chose not to ship something that would have hurt customers and the brand.'","task":"Write the 2-3 sentence reframe that makes the delay a deliberate, responsible decision.","tips":["Reframe a slip from failure to judgment — a choice made for a reason.","Contrast the two outcomes: shipping broken versus shipping right.","Own the decision as yours; 'I chose to hold it' beats 'it slipped.'"],"focus":["impact","clarity"],"placeholder":"This isn't a slip — it's a decision. Shipping in March means shipping a checkout that fails under load; I'm choosing to protect the launch and the brand by holding six weeks."},
    {"id":"narrative-eng-senior-23","level":"senior","profession":"engineer","title":"The candidate pitch as a story","scenario":"You're closing a VP candidate with three offers. A list of your tech stack and perks is forgettable. A narrative — the hard problem waiting for her, the scope she'll own, the mark she'll leave — is what a senior person signs up for.","task":"Write the 2-3 sentence narrative pitch built around the problem she'd own and the impact she'd have.","tips":["Senior candidates buy a story about the impact they'll have, not a feature list.","Center the specific hard problem and the scope she'd own outright.","Make her the protagonist of the next chapter, not a line on an org chart."],"focus":["impact","clarity"]},
    {"id":"narrative-eng-senior-24","level":"senior","profession":"engineer","title":"Pre-empt the board's competitive worry","scenario":"You're presenting your technology roadmap and know the board's unspoken worry is that competitors are moving faster. If you don't address it, it hangs over everything. Raise it yourself and reframe your deliberate strategy as an advantage.","task":"Write the 2-3 sentences that surface the competitive worry and reframe your approach as intentional.","tips":["Naming the board's unspoken fear disarms it and shows you're ahead of it.","Reframe 'slower' as 'concentrated' — fewer bets, executed fully.","Give one proof point that your focused approach is winning where it counts."],"focus":["impact","audience"]},
    {"id":"narrative-eng-senior-25","level":"senior","profession":"engineer","title":"The full persuasion case","scenario":"You have ten minutes to persuade the exec committee to fund the $3M platform consolidation. You need the whole toolkit: a vivid before/after, concrete stakes, a pre-empted objection, and a clear ask — assembled into one persuasive arc.","task":"Write the 4-sentence persuasion arc: the costly now, the better after, the pre-empted objection, the ask.","tips":["Assemble the pieces into one arc, not a list of tactics.","Open on the painful now, pivot to the after, defuse the top objection, close on the ask.","Every sentence should move the committee one step toward yes."],"focus":["impact","clarity"],"placeholder":"Today three platforms cost us $5M a year in incidents and slow every launch to a crawl. One platform cuts that to $1M and halves our release time. Yes, migration is risky — which is why we're phasing it with full rollback. I'm asking for $3M over two quarters to make it happen."}
  ],
  "delivering-hard-messages": [
    {"id":"hard-eng-senior-01","level":"senior","profession":"engineer","title":"Front-load the launch slip","scenario":"You have to tell the CEO the flagship launch she announced to the board will slip six weeks. Your draft eases in with context and reasons before the news. Clear is kind: she needs the bad news first, so she can act on it.","task":"Write the opening 2 sentences that deliver the slip first, then the one essential reason.","tips":["Burying bad news to soften it just makes the reader dig — lead with it.","The new date is the message; reasons come after, briefly.","Front-loading respects her need to react and re-plan immediately."],"focus":["clarity","impact"],"placeholder":"The launch will slip six weeks, to April 15. The payment vendor's certification came back late, and I couldn't recover the time without cutting the security review."},
    {"id":"hard-eng-senior-02","level":"senior","profession":"engineer","title":"The clean no to the board's request","scenario":"A board member wants you to commit to shipping the AI feature by Q2. You can't honestly commit, and a soft 'we'll try' will be heard as yes. Delivering a clean, respectful no is kinder than a hedge that breaks later.","task":"Write the 2-sentence clean no with the honest reason and what you can offer instead.","tips":["A clear no now prevents a broken yes later — that's the kindness.","Don't dress the no as a maybe; state it, then offer what's real.","Give the alternative you can commit to, so the no isn't a dead end."],"focus":["clarity","impact"],"placeholder":"I can't commit to Q2 — the model quality isn't there and forcing it would ship something that embarrasses us. What I can commit to is a working beta by Q2 and full launch by Q3."},
    {"id":"hard-eng-senior-03","level":"senior","profession":"engineer","title":"Behavior, impact, ask — with a director","scenario":"One of your directors dominates exec meetings, cutting off peers, and it's damaging the team. You need to give feedback that lands. The structure that works: name the specific behavior, its impact, then the ask — not vague 'be more collaborative.'","task":"Write the feedback in the behavior-impact-ask structure, 3 sentences.","tips":["Vague feedback ('be collaborative') can't be acted on — name the specific behavior.","State the impact factually, not as an accusation.","End with a clear, doable ask, not a character verdict."],"focus":["clarity","structure"],"placeholder":"In the last two exec meetings, you cut off Sarah and Tom before they finished. It's making them stop contributing, which costs us their input. I'm asking you to let people finish and to actively bring them in."},
    {"id":"hard-eng-senior-04","level":"senior","profession":"engineer","title":"Tell the customer their data was exposed","scenario":"A vulnerability exposed a small number of customer records, and you must notify the affected enterprise customer's CTO. The instinct is to minimize and cushion. Clear is kind: state plainly what happened, what data, and what you're doing.","task":"Write the opening 2-3 sentences: the exposure, the specific data, the action — no minimizing.","tips":["Minimizing a breach destroys trust when the full facts emerge — be straight.","State exactly what was exposed and what wasn't, precisely.","Lead with the facts and the action; apology follows, it doesn't replace them."],"focus":["clarity","audience"]},
    {"id":"hard-eng-senior-05","level":"senior","profession":"engineer","title":"The layoff message to your org","scenario":"You have to tell your engineering org that eight roles are being cut. There's no version that isn't painful. Clear and humane means delivering the hard fact directly, without corporate euphemism, while treating people with dignity.","task":"Write the opening 2-3 sentences that deliver the news directly and humanely.","tips":["Euphemisms ('rightsizing,' 'transitions') insult people facing job loss — say layoffs.","Deliver the fact clearly, then immediately address what affected people need to know.","Directness and compassion aren't opposites; vagueness is the unkind choice here."],"focus":["clarity","audience"]},
    {"id":"hard-eng-senior-06","level":"senior","profession":"engineer","title":"Decline the CEO's pet feature","scenario":"The CEO keeps pushing a feature you believe is technically unwise and low-value. You've deflected twice. You owe her a clear no with your reasoning, not another soft deferral that wastes both your time.","task":"Write the 2-3 sentence clear no to the CEO, with the reason and an open door.","tips":["Repeated soft deflection is less respectful than one honest no.","State your recommendation against it and the core reason.","Leave the door open — she can overrule, but she should do so informed."],"focus":["clarity","impact"]},
    {"id":"hard-eng-senior-07","level":"senior","profession":"engineer","title":"Tell your report he won't be promoted","scenario":"A senior engineer expected a promotion to staff this cycle and won't get it. Avoiding the directness would be cowardly and would deny him the chance to close the gap. Clear is kind: the decision, the specific reason, the path.","task":"Write the 3-sentence message: the decision, the specific gap, the concrete path.","tips":["Vague reasons for a no-promo leave people unable to fix anything — be specific.","State the decision plainly, then the one or two concrete gaps.","End with a real path, not a consolation."],"focus":["clarity","structure"]},
    {"id":"hard-eng-senior-08","level":"senior","profession":"engineer","title":"Admit the outage was our fault to the board","scenario":"The board wants to know what caused the outage that hit a major customer. The honest answer is an internal process failure, not an external cause. The temptation is to spread the blame; the credible move is to own it cleanly.","task":"Write the 2-sentence ownership statement: what we did wrong, no deflection.","tips":["Boards trust leaders who own failures more than ones who explain them away.","State the internal cause plainly, without a hedge toward external factors.","Ownership up front earns the credibility for the prevention plan that follows."],"focus":["clarity","impact"],"placeholder":"This was our failure — a change bypassed our own review process. No external factor was involved, and the gap that allowed it is on us to close."},
    {"id":"hard-eng-senior-09","level":"senior","profession":"engineer","title":"The no to a bigger budget","scenario":"A director asks you to approve doubling her team's headcount, and the honest answer is no — the money isn't there and the case isn't strong enough. She'll be disappointed. A clear no with reasoning beats a slow-walk that strings her along.","task":"Write the 2-3 sentence no with the honest reason and what would change your answer.","tips":["Slow-walking a no is crueler than delivering it — it wastes her planning.","State the no and the real constraint, not a vague 'not right now.'","Name what would make it a yes, so she has agency."],"focus":["clarity","impact"]},
    {"id":"hard-eng-senior-10","level":"senior","profession":"engineer","title":"Tell the CFO the project you championed failed","scenario":"An initiative you personally pushed and got funded has failed to deliver. You must tell the CFO. The instinct is to frame it as 'learnings' and 'pivots.' The credible move is to call the failure a failure and say what you'll do.","task":"Write the 2-3 sentence message that names the failure plainly and states the response.","tips":["'Learnings' and 'pivots' as euphemisms for failure fool no CFO — name it.","Owning a failure you championed is what protects your credibility for the next ask.","State what you're doing about it and what it cost, honestly."],"focus":["clarity","impact"]},
    {"id":"hard-eng-senior-11","level":"senior","profession":"engineer","title":"The peer whose team keeps blocking yours","scenario":"The head of data's team consistently misses commitments that block your launches, and it's now serious. You need to raise it with your peer directly — hard because it's cross-functional and public tension helps no one. Behavior, impact, ask, privately.","task":"Write the 3-sentence private message: the pattern, its impact on shared goals, the ask.","tips":["Frame it around shared goals, not blame, but don't soften the pattern out of existence.","Cite the specific missed commitments, not a general grievance.","Ask for a concrete change, and offer to help make it possible."],"focus":["clarity","structure"]},
    {"id":"hard-eng-senior-12","level":"senior","profession":"engineer","title":"Say no to the acquisition on tech grounds","scenario":"Corp dev is enthusiastic about a deal, but your technical assessment says the target's platform is a fatal liability. You must deliver a hard no on a deal people want. Clarity and evidence, not hedging, is what protects the company.","task":"Write the 2-3 sentence clear recommendation against the deal, with the deciding reason.","tips":["Softening a deal-breaker to be a team player is how bad acquisitions happen.","State your recommendation against, then the single deciding technical fact.","Be clear this is a recommendation you'd stake your judgment on."],"focus":["clarity","impact"]},
    {"id":"hard-eng-senior-13","level":"senior","profession":"engineer","title":"Tell a star engineer their conduct is a problem","scenario":"Your most brilliant engineer is also toxic in reviews, and two people have nearly quit over it. Talent doesn't excuse the behavior. You must deliver hard feedback that his conduct, not his work, is the issue — clearly, so it lands.","task":"Write the 3-sentence feedback: separate the valued work from the unacceptable behavior, with a clear line.","tips":["Praise for the work can't cushion the message about behavior — keep them separate and both clear.","Name the specific conduct and its concrete cost (people leaving).","Draw a clear line: this must change, and it's not negotiable."],"focus":["clarity","structure"]},
    {"id":"hard-eng-senior-14","level":"senior","profession":"engineer","title":"Deliver the security-freeze order nobody wants","scenario":"You're imposing a two-week production freeze over the holidays, which teams will hate because it blocks their launches. You must deliver an unpopular order clearly, own it as your decision, and not hide behind 'policy.'","task":"Write the 2-3 sentence message: the order, owned, with the honest why.","tips":["Hiding an unpopular decision behind 'policy' invites resentment — own it.","State the order and that it's your call.","Give the honest reason, and acknowledge the cost you're imposing."],"focus":["clarity","impact"],"placeholder":"I'm ordering a production freeze from December 20 to January 2 — this is my call. I know it blocks launches you care about; I'm choosing stability over velocity during the two weeks we have the fewest people to respond to an incident."},
    {"id":"hard-eng-senior-15","level":"senior","profession":"engineer","title":"Tell the board a target was missed","scenario":"You committed to the board that reliability would hit a specific number this year, and you missed it. At the next meeting you must report the miss. Front-load it; don't let it emerge halfway through a slide of good news.","task":"Write the 2-sentence report that leads with the miss, then the honest context.","tips":["Leading with good news to bury a miss reads as manipulation when found.","State the miss and the number plainly, up front.","Then the context — briefly, as explanation, not excuse."],"focus":["clarity","impact"]},
    {"id":"hard-eng-senior-16","level":"senior","profession":"engineer","title":"The uncomfortable truth about a vendor relationship","scenario":"Your CEO has a personal relationship with a vendor whose product is now failing you, and you need to recommend leaving them. The hard part is the personal dimension. You must deliver the recommendation on the merits, plainly, without letting the relationship distort it.","task":"Write the 2-3 sentence recommendation that states the vendor problem and the recommendation to leave, respectfully.","tips":["A personal relationship can't be a reason to soften a business-critical recommendation.","State the vendor's failures factually, then the recommendation.","Acknowledge the relationship exists, then set it aside on the merits."],"focus":["clarity","precision"]},
    {"id":"hard-eng-senior-17","level":"senior","profession":"engineer","title":"Tell your team the reorg cuts their scope","scenario":"The reorg means one of your teams loses a product area they're proud of. They'll feel demoted. You must deliver this clearly and honestly, without pretending it's a promotion or burying the loss in 'strategic alignment.'","task":"Write the 2-3 sentence message that names the change honestly and respects what they built.","tips":["Dressing a scope loss as a win insults people who see it clearly — be honest.","Name what's moving away and acknowledge what they built.","Then give the honest reason and what their focus becomes."],"focus":["clarity","audience"]},
    {"id":"hard-eng-senior-18","level":"senior","profession":"engineer","title":"The no to the customer's impossible demand","scenario":"After the outage, your biggest customer demands a contractual guarantee of zero downtime or they walk. You can't promise that. You must say no to a customer holding real leverage, clearly, while fighting to keep them.","task":"Write the 2-3 sentence response: the honest no, then the real commitment that keeps them.","tips":["Agreeing to an impossible term to save the deal creates a worse breach later.","Decline the impossible clearly, explaining why no honest vendor could promise it.","Immediately offer the strong, real commitment — and a reason to trust it."],"focus":["clarity","impact"]},
    {"id":"hard-eng-senior-19","level":"senior","profession":"engineer","title":"Give the CEO feedback on undermining you","scenario":"The CEO has twice overridden your technical decisions in front of your team, undermining your authority. This is hard feedback to deliver upward, but necessary. Behavior, impact, ask — calmly and privately.","task":"Write the 3-sentence upward feedback: the specific behavior, its impact, your ask.","tips":["Upward hard feedback requires more precision, not more hedging — be specific and calm.","Cite the two specific instances, factually.","State the impact on your ability to lead, then a clear, reasonable ask."],"focus":["clarity","structure"]},
    {"id":"hard-eng-senior-20","level":"senior","profession":"engineer","title":"Announce the platform everyone loves is being killed","scenario":"You're sunsetting an internal platform that a passionate group of engineers built and love. They'll be upset. You must deliver the decision clearly, honor the work, and not pretend the decision is reversible or up for debate.","task":"Write the 2-3 sentence announcement: the decision, honoring the work, no false hope.","tips":["Leaving false hope that a settled decision might reverse is unkind — be clear it's final.","Honor what they built genuinely before stating it's being retired.","Give the honest reason, then what happens to the people."],"focus":["clarity","audience"]},
    {"id":"hard-eng-senior-21","level":"senior","profession":"engineer","title":"Tell the CFO the estimate was wrong","scenario":"The infrastructure project you scoped at $2M is now tracking to $3.5M. You have to tell the CFO the estimate was significantly off. Front-load the number; own the miss on the estimate, not just the overrun.","task":"Write the 2-3 sentence message: the new number first, then honest accountability for the estimate.","tips":["Lead with the new number — that's what the CFO needs to replan around.","Own the estimating miss specifically, not just the cost.","Then what you've done to make the new number reliable."],"focus":["clarity","precision"],"placeholder":"The infrastructure project is now tracking to $3.5M, not the $2M I scoped. My original estimate missed the migration complexity — that's on me, and I've had it independently re-estimated so this number holds."},
    {"id":"hard-eng-senior-22","level":"senior","profession":"engineer","title":"The hard message about a director's team culture","scenario":"One of your directors runs a team with a burnout culture — long hours, high attrition — that she seems proud of. You must tell her it's a problem, which she won't want to hear. Behavior, impact, ask, without attacking her.","task":"Write the 3-sentence feedback on the culture pattern: the behavior, the impact, the ask.","tips":["Challenging something someone is proud of requires precision and care, not softness.","Name the pattern with data — attrition, hours — not impressions.","Frame the impact on outcomes she cares about, then a clear ask."],"focus":["clarity","structure"]},
    {"id":"hard-eng-senior-23","level":"senior","profession":"engineer","title":"Say no to the exec team's timeline","scenario":"The exec team has set a launch timeline that engineering cannot safely hit, and everyone's nodding along. You must be the one to say no, clearly, in the room, before commitments are made externally on a date you'll miss.","task":"Write the 2-3 sentence in-room no: the timeline isn't safe, why, and what is achievable.","tips":["Silence in the room becomes a broken external promise — say the no now.","State plainly that the date isn't safe and the specific reason.","Immediately offer the date you can commit to, so it's not just an objection."],"focus":["clarity","impact"]},
    {"id":"hard-eng-senior-24","level":"senior","profession":"engineer","title":"Deliver disappointing news to the whole org","scenario":"Bonuses are flat this year despite the team's hard work, and you have to tell the org at all-hands. Sugarcoating insults their intelligence. You must deliver the disappointing fact clearly, acknowledge the effort, and be honest about why.","task":"Write the 2-3 sentence message: the flat-bonus fact, the acknowledgment, the honest why.","tips":["People know when they're being managed — deliver the hard fact straight.","Acknowledge the effort genuinely, but don't use it to soften the fact into vagueness.","Give the honest business reason; respect them enough to explain."],"focus":["clarity","audience"]},
    {"id":"hard-eng-senior-25","level":"senior","profession":"engineer","title":"The hardest message: stepping back a beloved leader","scenario":"You've decided a well-liked senior director needs to move out of management into an individual-contributor role — a demotion in everything but title. You must deliver it directly, preserve his dignity, and not let sympathy blur the message into confusion about whether it's optional.","task":"Write the 3-sentence message: the decision, the honest reason, the dignity — with no ambiguity that it's decided.","tips":["Sympathy that blurs whether the decision is final is the cruelest outcome — be unambiguous.","State the decision and the honest reason clearly, up front.","Preserve dignity through respect and a real path, not through vagueness about the decision."],"focus":["clarity","structure"]}
  ],
  "putting-it-together": [
    {"id":"together-eng-senior-01","level":"senior","profession":"engineer","title":"The board narrative, end to end","scenario":"You have one slide and three minutes for the board on the year's technology story. It needs a governing thesis, a clear recommendation, honest risk, and no jargon — everything the course has practiced, under a hard length constraint.","task":"Write the complete 4-sentence board narrative: thesis, evidence, risk, ask.","tips":["Under a tight constraint, every sentence must do one job — thesis, proof, risk, ask.","Lead with the thesis; the board decides whether to keep listening in ten seconds.","Name the risk honestly — it makes the ask credible, not weaker."],"focus":["structure","impact"]},
    {"id":"together-eng-senior-02","level":"senior","profession":"engineer","title":"Match register: Slack vs board memo","scenario":"You need to communicate the same fact — the migration is done, early and under budget — in two channels: a quick #exec Slack and a formal board memo paragraph. Same fact, different register and length for each.","task":"Write both versions: the one-line Slack and the two-sentence board-memo version.","tips":["Channel dictates register: Slack is fast and flat, a board memo is measured and complete.","The fact is identical; the packaging changes with the reader and medium.","Don't write the board memo in Slack, or the Slack in board prose."],"focus":["audience","concision"],"placeholder":"Slack: Migration's done — two weeks early, $400K under. / Memo: The platform migration completed on [date], two weeks ahead of schedule and $400K under budget."},
    {"id":"together-eng-senior-03","level":"senior","profession":"engineer","title":"Edit like the reader: the CFO's ten seconds","scenario":"You've drafted a dense investment memo. Now edit it as the CFO who will spend ten seconds on the first paragraph before deciding whether to read on. Read your own opening the way she will, and cut what she won't value.","task":"Rewrite your opening paragraph as the version that survives a CFO's ten-second read.","tips":["Editing like the reader means asking what she'll skip and cutting it first.","The ask and the headline number belong in the first two lines.","Anything she has to be patient to reach probably shouldn't be there."],"focus":["audience","concision"]},
    {"id":"together-eng-senior-04","level":"senior","profession":"engineer","title":"The incident comms under real constraint","scenario":"An outage is ongoing. In the next five minutes you must post a customer status update, send an exec Slack, and brief your on-call lead — three audiences, three registers, all true to the same facts, all under time pressure.","task":"Write the customer status line and the exec Slack line — same incident, correct register for each.","tips":["Same facts, three audiences: customers need reassurance, execs need impact, on-call needs specifics.","Under time pressure, lead each with what that audience most needs first.","Never let the registers bleed — customer-facing calm, exec-facing precise."],"focus":["audience","clarity"],"placeholder":"Customer: Checkout is currently down; we're on it and will update by 3:00 p.m. ET. / Exec: Checkout down 12 min, ~3% txns failing, cause isolated, ETA 20 min."},
    {"id":"together-eng-senior-05","level":"senior","profession":"engineer","title":"The QBR opening that does everything","scenario":"Your QBR opening with the CEO and CFO has 30 seconds to give the quarter's verdict, own a miss, signpost the structure, and set up the ask. It's the whole course compressed into an opening.","task":"Write the 3-4 sentence QBR opening: verdict, owned miss, signpost, and the ask to come.","tips":["Open with the scoreboard, own the miss in the same breath — that's credibility.","Signpost the structure so they know the shape of the next twenty minutes.","Tee up the ask early so they listen for the decision."],"focus":["structure","impact"]},
    {"id":"together-eng-senior-06","level":"senior","profession":"engineer","title":"Persuade and deliver hard news together","scenario":"You must tell the CEO the launch slips six weeks AND persuade her the slip is the right call, in one message. It has to front-load the bad news and reframe it as a responsible decision, without contradiction.","task":"Write the 3-sentence message that delivers the slip and persuades it was right.","tips":["Front-load the hard fact, then immediately reframe it as your deliberate choice.","The persuasion rides on owning the decision, not on softening the news.","One clear reason for the choice beats three defensive ones."],"focus":["impact","structure"],"placeholder":"The launch moves to April 15 — a six-week slip. I made that call deliberately: shipping in March meant a checkout that fails under load, and protecting the launch is worth the six weeks. Here's how I'm using the time."},
    {"id":"together-eng-senior-07","level":"senior","profession":"engineer","title":"The vendor negotiation email, fully assembled","scenario":"You're opening the cloud-renewal negotiation by email. It needs presence (a firm anchor), structure (position, rationale, next step), concision (no throat-clearing), and a persuasive frame (why yes helps them) — all in one short message.","task":"Write the complete 3-4 sentence negotiation opener.","tips":["Anchor firmly in the first line — that's presence and structure at once.","Fold in one reason yes serves them; skip the pleasantries entirely.","End with a concrete next step and date to keep momentum."],"focus":["structure","impact"]},
    {"id":"together-eng-senior-08","level":"senior","profession":"engineer","title":"Translate up and lead with the point","scenario":"You're explaining to a sales-background CEO why feature velocity dropped, and you must both translate the technical cause into business terms AND lead with the point, in three sentences. Two skills, one tight message.","task":"Write the 3-sentence explanation: point first, in her business terms, cause second.","tips":["Lead with the business fact (velocity is down, here's why) before any mechanism.","Translate the cause into launch-speed terms, not engineering terms.","Keep it to what she can act on — a decision or a reassurance."],"focus":["audience","clarity"],"placeholder":"Feature velocity dropped about 40% this quarter, and it's fixable. The cause is our oldest system — every change to it now touches shortcuts from 2021. I'm asking to spend one quarter fixing that so speed comes back."},
    {"id":"together-eng-senior-09","level":"senior","profession":"engineer","title":"The all-hands that informs and rallies","scenario":"At the engineering all-hands you must deliver a hard truth (hiring missed, budgets flat) and still rally the org around the year ahead. The message has to be honest about the hard parts and genuinely motivating, without the two undercutting each other.","task":"Write the 3-4 sentence all-hands segment that delivers the hard truth and rallies.","tips":["Honesty about the hard parts is what makes the rally credible — don't skip it.","Deliver the hard truth cleanly, then pivot to the genuine reason for optimism.","Motivation built on a lie collapses; build it on a real forward story."],"focus":["audience","impact"]},
    {"id":"together-eng-senior-10","level":"senior","profession":"engineer","title":"The one-pager the board will actually read","scenario":"The CEO asked for a one-page 'state of engineering' for the board packet. It must have a governing thesis, three claims with evidence, honest risk, and survive being read cold by a non-technical director — the whole toolkit on one page.","task":"Write the thesis sentence and the three one-line claims beneath it.","tips":["The thesis is a verdict the board can quote; the claims are its pillars.","Each claim carries a number and no jargon — a director reads it cold.","Include the honest risk as one of the lines, not an omission."],"focus":["structure","audience"],"placeholder":"Engineering is healthy and fast, with one risk worth watching. Delivery: shipped both launches, up 30% velocity. Reliability: 99.95% uptime, best ever. Risk: our depth is concentrated in two teams."},
    {"id":"together-eng-senior-11","level":"senior","profession":"engineer","title":"Answer under pressure with full command","scenario":"In the board meeting you're hit with 'Why should we fund more infrastructure when the last investment didn't show results?' You must answer the actual question, meet the challenge with specifics, own the prior gap, and keep your ask alive — all composed, in three sentences.","task":"Write the 3-sentence response integrating the answer, the specifics, the ownership, and the ask.","tips":["Answer the real question first, then meet it with a specific, not a defense.","Own the prior gap honestly — that's what makes the new ask credible.","Return to the ask at the end so the challenge doesn't bury it."],"focus":["clarity","impact"]},
    {"id":"together-eng-senior-12","level":"senior","profession":"engineer","title":"The customer apology letter, complete","scenario":"After the four-hour outage, the customer letter must acknowledge, state impact precisely, own the cause, commit to prevention, and offer recompense — in the right order, in plain language, in under 150 words. Every course skill, one artifact.","task":"Write the complete letter in five sentences, one per part, in the load-bearing order.","tips":["Fixed order: acknowledge, impact, cause, prevention, recompense — each sentence does one job.","Impact before cause: customers care what happened to them before why.","Plain language throughout — a technical customer still wants human, precise words."],"focus":["structure","audience"]},
    {"id":"together-eng-senior-13","level":"senior","profession":"engineer","title":"The Slack that respects the channel","scenario":"You need to update #exec that the $2M deal's SSO blocker is fixed. The whole skill here is register and channel: three seconds to read, lead with what they care about, no memo prose, but complete enough to act on.","task":"Write the exec-Slack update: one line, lead with the deal, complete.","tips":["Match the channel: exec Slack is scanned, not studied — front-load the payoff.","The deal, not the technical fix, is the headline for this audience.","One line, but with enough that the CEO can relay it onward."],"focus":["audience","concision"],"placeholder":"SSO blocker on the $2M Meridian deal is fixed and verified — sales is unblocked to close."},
    {"id":"together-eng-senior-14","level":"senior","profession":"engineer","title":"The investment memo, top to bottom","scenario":"Your tech-debt investment memo needs to lead with the ask, structure the case in three pillars, price inaction, pre-empt the affordability objection, and close with a decision date. Assemble the full argument under a one-page limit.","task":"Write the memo's opening ask sentence and the three pillar headlines beneath it.","tips":["Open with the ask and its payoff; the pillars carry the weight.","Each pillar is a claim with a number, not a topic.","One pillar should price inaction — that pre-empts 'can't afford it.'"],"focus":["structure","impact"],"placeholder":"I'm asking for $3M over two quarters to retire the legacy order system. Pillar 1: it causes 60% of our incidents. Pillar 2: it doubles every feature timeline. Pillar 3: doing nothing costs us $5M a year."},
    {"id":"together-eng-senior-15","level":"senior","profession":"engineer","title":"The reorg announcement, fully realized","scenario":"You're announcing a team merge to the org. It needs the change front-loaded, structured as what/why/next, honest about what people fear, and pitched to the people in it — the complete hard-message-plus-audience toolkit in one announcement.","task":"Write the announcement's first three sentences: the change, the why, and what doesn't change.","tips":["Lead with the change itself; anxious readers can't process preamble.","Separate what changes from why cleanly, then address the fear directly.","Saying what doesn't change is half of what the org needs to hear."],"focus":["structure","audience"]},
    {"id":"together-eng-senior-16","level":"senior","profession":"engineer","title":"The build-vs-buy recommendation, complete","scenario":"Your build-vs-buy memo to the CFO and CEO must lead with the verdict, structure the case on cost/risk/speed, use precise numbers, own the recommendation, and pre-empt the strongest counterargument — the whole course in one decision document.","task":"Write the opening verdict sentence and the one sentence that raises and answers the strongest objection.","tips":["Verdict first, in one sentence, with the number that decides it.","Raise the best counterargument yourself and answer it — that's presence plus persuasion.","Precise numbers, owned recommendation, no hedge."],"focus":["structure","precision"],"placeholder":"Recommendation: buy — it's 3x cheaper over five years and ships in one quarter, not four. The obvious objection is vendor lock-in; we've mitigated it with a data-portability clause and an exit plan we've costed."},
    {"id":"together-eng-senior-17","level":"senior","profession":"engineer","title":"The two-audience deprecation notice","scenario":"You're deprecating an API version a top customer uses. One email must serve the customer's VP (why, cost, timeline) and their engineers (endpoints, dates) — leading at the senior altitude, with technical detail signposted below. Structure and audience together.","task":"Write the VP-level opening 2 sentences and the one-line signpost to the technical section.","tips":["Lead at the most senior reader's altitude; stack detail beneath.","The VP needs why, what breaks, and what it costs their team.","Signpost the technical section explicitly so engineers can jump to it."],"focus":["audience","structure"],"placeholder":"We're retiring API v1 on June 30 to move everyone to the faster, more reliable v2. For your team this means updating three endpoints, with our support throughout. [Migration details for your engineers follow below.]"},
    {"id":"together-eng-senior-18","level":"senior","profession":"engineer","title":"The spoken exec-staff answer, fully composed","scenario":"In exec staff the CEO asks, unprompted, 'What's our biggest engineering risk right now?' You have 45 seconds. The answer needs PREP structure, a real recommendation, one precise number, and composure — the full toolkit, spoken, on the spot.","task":"Write the 4-sentence spoken answer: point, reason, example with a number, point.","tips":["Point first, even unprompted — name the risk in one sentence.","One example with a number beats three abstractions.","Return to the point at the end and attach what you're doing about it."],"focus":["structure","clarity"],"placeholder":"Our biggest risk is key-person concentration on the payment platform. One engineer holds most of that knowledge, and he could leave. Last month a two-day absence stalled a critical fix. So the risk is real, and I'm asking to fund a staff hire to remove it."},
    {"id":"together-eng-senior-19","level":"senior","profession":"engineer","title":"The diligence summary the deal team pastes","scenario":"Your acquisition-target tech assessment must give a clear verdict, structure the risks into categories, quantify each, use language non-technical corp-dev will paste verbatim, and be honest about deal-changing findings. The full toolkit in a document you don't control the reuse of.","task":"Write the verdict sentence and one quantified, paste-ready risk sentence.","tips":["Write the sentences you want quoted — corp dev copies, they don't translate.","Verdict first, then risks as scenario-plus-cost.","Every claim survives a skeptical reader with no you present to explain."],"focus":["audience","precision"],"placeholder":"The product is strong, but plan on a $5M platform rebuild within 18 months. Their single-region setup means one data-center failure takes the product fully down, with no tested recovery — a real, dealable risk we can price."},
    {"id":"together-eng-senior-20","level":"senior","profession":"engineer","title":"The change-freeze order, complete","scenario":"You're ordering a holiday production freeze. The message must lead with the order, own it as your decision, give the honest reason, name the exception process, and land with authority — hard-message delivery, presence, and structure combined.","task":"Write the complete 3-sentence order: the freeze, owned, the reason, the exception path.","tips":["Lead with the order — what stops, when, for whom.","Own it as your call and give one honest reason.","Name the exception process up front to head off the reply-all questions."],"focus":["structure","impact"],"placeholder":"Production change freeze, December 20 to January 2, all teams — this is my call. We have the fewest people available to respond to an incident over the holidays, and stability wins over velocity for those two weeks. For a genuine emergency, escalate to me directly for an exception."},
    {"id":"together-eng-senior-21","level":"senior","profession":"engineer","title":"The investor-call soundbite, engineered","scenario":"The CEO wants you to give investors a 20-second infrastructure soundbite that frames the platform as a moat, uses one memorable number, translates into their terms, and survives being quoted. Concision, audience, precision, and narrative in three sentences.","task":"Write the 2-3 sentence investor soundbite.","tips":["One number, chosen to survive being quoted out of context.","Frame infrastructure as a moat — why growth stays profitable.","Translate into analyst terms: margin, scale, moat — not architecture."],"focus":["audience","impact"],"placeholder":"Our platform is why we can double customers while engineering headcount grows just 20% — that's not a cost center, it's why our margins expand as we scale."},
    {"id":"together-eng-senior-22","level":"senior","profession":"engineer","title":"The upward feedback, fully structured","scenario":"You need to give the CEO feedback that overriding your technical calls in front of your team undermines you. It requires behavior-impact-ask structure, presence to deliver upward, precision on the instances, and composure — every hard-message skill, aimed up.","task":"Write the 3-sentence upward feedback: specific behavior, its impact, the clear ask.","tips":["Precision, not hedging, is what makes upward feedback land — cite the specific instances.","State the impact on your ability to lead, factually.","End with a reasonable, doable ask, delivered calmly."],"focus":["structure","clarity"]},
    {"id":"together-eng-senior-23","level":"senior","profession":"engineer","title":"The postmortem exec summary, complete","scenario":"Your outage postmortem's executive summary must lead with impact, state the cause in active voice, name the prevention with a date, be precise on the blast radius, and be honest about fault — the full toolkit in a summary execs will actually read.","task":"Write the 3-sentence exec summary: impact, cause, prevention-with-date.","tips":["Lead with the precise blast radius, then the cause in active voice.","Own the fault plainly — no passive voice hiding the actor.","The prevention needs a date, or it reads as sentiment."],"focus":["structure","precision"],"placeholder":"For 47 minutes, ~3% of transactions failed — about 1,200 checkouts, mostly enterprise. A configuration change bypassed our mandatory review, which is on us. We're adding an automated gate that blocks unreviewed changes, live by March 15."},
    {"id":"together-eng-senior-24","level":"senior","profession":"engineer","title":"The whole platform pitch, live","scenario":"You have five minutes with the exec committee to win $3M for platform consolidation. You need a governing thesis, a before/after, precise numbers, a pre-empted objection, an owned recommendation, and a clear ask — everything the course taught, delivered as one live pitch.","task":"Write the complete 5-sentence pitch: thesis, before/after with numbers, objection pre-empted, ask.","tips":["Open on the thesis, make the before/after vivid and numbered.","Pre-empt the strongest objection inside your own case.","Close on the ask with a decision date — don't let it drift."],"focus":["impact","clarity"],"placeholder":"One platform instead of three is the highest-return investment we can make this year. Today, three platforms cost $5M a year in incidents and stretch every launch to six weeks; consolidated, that's $1M and two weeks. The migration is the obvious risk — we've phased it with full rollback and no big-bang cutover. I'm asking for $3M over two quarters, and I'd like a decision by end of month."},
    {"id":"together-eng-senior-25","level":"senior","profession":"engineer","title":"The capstone: a week's worth in one message","scenario":"It's Friday and the CEO wants one message covering the week: the deal-unblocking fix landed, the launch slips two weeks, hiring is behind, and you need a headcount decision Monday. Multiple messages, one artifact — lead with what matters, structure it, be honest, and make the ask unmissable.","task":"Write the complete 4-5 sentence weekly message: lead item, the slip owned, the status, the ask with its deadline.","tips":["Rank by what moves the company — the deal fix leads, not chronology.","Own the slip in one clean sentence; don't bury it or over-explain.","Make the ask and its Monday deadline unmissable — that's the action item.","Edit it as the CEO reading Friday evening: what does she need, in what order?"],"focus":["structure","audience"],"placeholder":"Headline: the SSO blocker on the $2M Meridian deal is fixed — sales can close. Two things need your eye: the payments launch slips two weeks to protect the security review (my call), and hiring is 4 behind pace. The one decision I need: approve the two payments hires by Monday, or the launch date is at real risk. Details on each below."}
  ],
};
